INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('c5cd98e4-77df-4c74-81ed-9e2c6daefd85', 'e4ea5770-4d2c-4e3d-8b95-defada7816b8', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'other', 'pathway', 0, 1, 2, 2, 1, 'Only a single line of evidence is present: an Open Targets database entry noting ULIPRISTAL ACETATE as a Phase 2 candidate for PMDD acting via progesterone receptor modulation. No independent mechanistic studies converge here.', 'The claim derives from a curated drug-target database (Open Targets) indicating Phase 2 clinical staging, which implies human-relevant development, but no actual study design, data, or model is described. This is a registry annotation rather than experimental rigor.', 'The mechanism is explicitly a progesterone receptor modulator acting on the progesterone receptor, a well-defined single named target. The claim directly names the drug''s specific action on that target.', 'PMDD is mechanistically linked to abnormal sensitivity to progesterone/allopregnanolone fluctuations, so a progesterone receptor modulator targeting the progesterone receptor is a strong target-phenotype fit. The claim''s named target aligns with the recognized pathophysiology of PMDD.', 'Only one signal is present, so there is no opportunity for multiple mechanistic signals to agree or disagree. The single entry is internally coherent but cannot demonstrate consistency across lines.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Ulipristal acetate is a Phase 2 clinical candidate for PMDD acting as a progesterone receptor modulator on the progesterone receptor per Open Targets.', 'By modulating the progesterone receptor, ulipristal acetate may blunt the abnormal progesterone-related signaling thought to drive PMDD symptoms.', '{6873521f-0ecb-4eba-8493-2f81172b488a}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:03:50.672057+00:00', '2026-06-16T18:03:50.672118+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('50ba0237-b01e-495c-96ae-829d53183ec3', 'e5e1c9ed-6926-4b12-a042-0ad4890672b2', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'other', 'pathway', 0, 1, 1, 1, 1, 'Only a single mechanistic line is provided: drospirenone acting as a mineralocorticoid receptor antagonist on NR3C2 (claim 1). No independent converging lines (e.g., progesterone receptor activity, anti-androgenic action, GABAergic effects) are cited.', 'The evidence is a database (Open Targets) annotation citing a Phase 2 clinical stage for PMDD (claim 1), which is human-relevant context, but no actual study design, model, or outcome data are presented. This is a curated target-mechanism statement rather than experimental rigor.', 'The claim names a specific molecular target and action—mineralocorticoid receptor (NR3C2) antagonism (claim 1)—but drospirenone is known to be pharmacologically promiscuous (progestogenic, anti-androgenic), and only one target is documented here, limiting demonstrated specificity.', 'The single annotated mechanism (mineralocorticoid receptor antagonism, claim 1) plausibly relates to fluid retention/bloating symptoms in PMDD and is consistent with a Phase 2 clinical candidacy, but the claim does not link the target directly to core mood/affective phenotypes of PMDD.', 'With only one mechanistic claim there is no internal contradiction, but neither is there convergence among multiple signals (claim 1). Consistency cannot be strongly affirmed from a single data point.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Drospirenone is a Phase 2 clinical candidate for PMDD whose annotated mechanism is mineralocorticoid receptor (NR3C2) antagonism.', 'By antagonizing the mineralocorticoid receptor (NR3C2), drospirenone may counteract aldosterone-mediated fluid retention and related premenstrual symptoms in PMDD.', '{060ab134-7ae3-4dff-9d0e-8c3f59af4cb1}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:03:50.867885+00:00', '2026-06-16T18:03:50.867899+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
