pathway evidence is provided.', NULL, '{4fdd0a83-16a2-40bb-8781-3d9ed0657c7b}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:03:53.870513+00:00', '2026-06-16T18:03:53.870551+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
