INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('942c35dd-14d2-470b-88fd-587f3e6b32a8', '2e979d12-b11d-4e77-99d7-6171b6fda089', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'other', 'pathway', 0, 1, 2, 1, 1, 'Only a single line of evidence is present — an Open Targets database entry stating LEVONORGESTREL is a progesterone receptor agonist clinical candidate for PMDD. No independent mechanistic lines converge to support the claim.', 'The claim cites a curated database (Open Targets) reporting a PHASE_3 clinical stage, implying human-relevant clinical development, but no actual study data, models, or outcomes are presented. The evidence is purely a target-annotation reference rather than experimental results.', 'The mechanism is precisely named: levonorgestrel acts as a progesterone receptor agonist on the progesterone receptor target, a specific and well-defined molecular action per the Open Targets annotation.', 'Progesterone receptor modulation is mechanistically relevant to PMDD given the condition''s link to the luteal phase and progesterone/allopregnanolone fluctuations, and the PHASE_3 stage suggests target-phenotype fit. However, the single claim provides no direct phenotypic data linking PR agonism to symptom improvement.', 'With only one claim there is no contradictory signal, but neither is there corroborating direction from multiple sources. Internal consistency cannot be meaningfully assessed from a single database annotation.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Per Open Targets, levonorgestrel is a Phase 3 clinical candidate for PMDD acting as a progesterone receptor agonist.', 'Levonorgestrel acts as an agonist at the progesterone receptor, potentially modulating luteal-phase progesterone signaling implicated in PMDD.', '{56dbcc98-c450-4e9e-86b3-729a6952c004}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:03.688843+00:00', '2026-06-16T18:04:03.688865+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('327b2061-815c-4d28-9698-941a1a615bd1', 'e9003ea1-ee30-4de7-96ff-158a42eed2ce', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'other', 'pathway', 0, 1, 1, 1, 1, 'Only a single source (Open Targets) provides one mechanistic line: ethinyl estradiol as an estrogen receptor alpha agonist on ESR1. No independent converging mechanistic lines are presented.', 'The claim derives from a curated database citing a PHASE_3 clinical stage for PMDD, implying human-relevant clinical development. However, no actual study data, models, or results are provided to assess strength or recency directly.', 'The claim specifies a defined mechanism (estrogen receptor alpha agonist on target ESR1), which is moderately specific. However, ethinyl estradiol broadly engages estrogen receptors and is not selectively targeted, limiting specificity.', 'Estrogen receptor modulation has biological relevance to PMDD given the condition''s hormonal basis, and a PHASE_3 designation suggests target-phenotype fit. But the single claim does not articulate how ER-alpha agonism addresses PMDD symptom pathophysiology.', 'With only one mechanistic claim available, there are no conflicting signals, but also no multiple signals to confirm directional agreement. Consistency cannot be meaningfully assessed beyond the single positive annotation.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Ethinyl estradiol is annotated as a Phase 3 clinical candidate for PMDD acting as an estrogen receptor alpha agonist on ESR1.', 'Ethinyl estradiol acts as an estrogen receptor alpha agonist on ESR1, potentially modulating hormonal pathways implicated in PMDD.', '{781ae8bd-9772-40a0-990c-e50253b6629f}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:04.980074+00:00', '2026-06-16T18:04:04.980085+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('f1a103b5-666c-4b26-b975-aeab54c91060', '7f6ed8f9-842a-42ca-b224-7ca9e3fcf95a', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'other', 'pathway', 0, 1, 2, 1, 1, 'Only a single line of evidence is provided: one Open Targets database entry stating sertraline is a serotonin transporter inhibitor clinical candidate for PMDD. No independent mechanistic lines converge.', 'The claim derives from a curated database entry (Open Targets) citing a PHASE_1_2 clinical stage, which is human-relevant but provides no actual study data, models, or outcomes. It is a regulatory/annotation statement rather than experimental evidence.', 'The claim names a precise molecular mechanism: serotonin transporter inhibition acting on solute carrier family 6 member 4 (SLC6A4/SERT). This is a well-defined, specific drug-target action.', 'Serotonergic modulation via SERT inhibition is a recognized therapeutic rationale for PMDD, and the entry links the target to the named condition. However, no claim explicitly connects the target mechanism to the PMDD phenotype beyond the database annotation.', 'With only one claim there is no opportunity for signals to conflict, but neither is there convergence; the single positive annotation is internally consistent only by default.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Per Open Targets, sertraline is a clinical-stage (Phase 1/2) serotonin transporter (SLC6A4) inhibitor candidate for PMDD.', 'Sertraline inhibits the serotonin transporter (SLC6A4/SERT), increasing synaptic serotonin availability, which is the proposed basis for its effect in PMDD.', '{4512d7e9-bd58-4161-aa0d-c6629c0545c8}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:07.449578+00:00', '2026-06-16T18:04:07.449603+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('2d41e68c-45aa-4a1e-b884-64b586f3fe78', '6ac3c4b2-178a-4b38-9c40-6adef793e2b8', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 2, 1, 1, 'Only a single source (Open Targets) is cited, establishing one line: that cabergoline is a clinical candidate for endometriosis via D2 receptor agonism. No independent mechanistic lines (e.g., antiangiogenic data, lesion regression studies) converge in the provided claims.', 'The claim references a PHASE_2 clinical candidate status per Open Targets, implying human-relevant clinical development, but no actual study data, models, or outcomes are presented. The evidence is a database annotation rather than reported experimental or trial results.', 'The single claim specifies a precise molecular action: dopamine D2 receptor agonist acting on dopamine receptor D2. This is a well-defined, target-specific mechanism for cabergoline.', 'The claim ties cabergoline''s D2 agonism to endometriosis as a clinical candidate, but provides no mechanistic rationale linking D2 receptor activity to the endometriosis phenotype (e.g., via antiangiogenic VEGF effects). Plausibility is supported only by candidate status, not an explained target-phenotype fit.', 'With only one claim, there are no multiple signals to compare; the single annotation is internally consistent but cannot demonstrate convergence. No contradicting evidence is present, but neither is corroborating directionality.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Cabergoline is annotated as a Phase 2 clinical candidate for endometriosis acting as a dopamine D2 receptor agonist per Open Targets.', 'Cabergoline acts as a dopamine D2 receptor agonist, a pathway that may be relevant to endometriosis (potentially via antiangiogenic effects), though the mechanistic link to the phenotype is not detailed in the claims.', '{fa385edb-5ea5-4e32-8b8a-f05fb3a29ee4}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:12.897091+00:00', '2026-06-16T18:04:12.897130+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('b8b57a3a-5ad4-4d15-aadc-1fc0eb728475', 'aedfa810-bac6-4c5b-a525-52046b55f356', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 0, 0, 0, 0, 'The single verified claim only states that VITAMIN E is a Phase 2 clinical candidate for endometriosis per Open Targets; it provides no mechanistic lines of evidence whatsoever. There is no convergence of independent pathways to assess.', 'The claim is a database annotation of clinical stage, not a mechanistic model with human-relevant data. No experimental or pharmacological model is described.', 'No molecular target or specific mechanism of action of vitamin E on endometriosis is named in the claim. Specificity of action cannot be evaluated from a clinical-stage annotation alone.', 'The claim does not link any target to the endometriosis phenotype; it only reports a clinical development stage. No target-phenotype fit is described.', 'With only one annotation and no mechanistic signals, there is nothing to assess for directional agreement. No converging or conflicting mechanistic data are present.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Per Open Targets, vitamin E is a Phase 2 clinical candidate for endometriosis, but no mechanistic pathway evidence is provided.', NULL, '{32d2bce1-dd68-412e-bf7e-3737e3b9fdec}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:13.376429+00:00', '2026-06-16T18:04:13.376451+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('df48835f-0ee4-46ad-b00d-668cab47ea9b', 'dcd5ca46-ee57-4d35-b7e1-07b887d30b22', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 0, 0, 1, 0, 'Only a single claim is provided, an Open Targets database entry stating DIENOGEST is an approved clinical candidate for endometriosis. No independent mechanistic lines are described, so there is no convergence to assess.', 'The sole claim is a regulatory/database status entry from Open Targets, not a mechanistic model (human, animal, or in-vitro). No experimental data of any kind is cited.', 'The claim identifies DIENOGEST as a small-molecule clinical candidate but provides no information about its molecular target or mode of action on endometriosis. No specificity of drug-target action can be evaluated.', 'DIENOGEST is noted as having reached maximum clinical stage APPROVAL for endometriosis, which implies an established target-phenotype fit, though no mechanism is described in the claim. The approval status lends partial plausibility without explicit mechanistic support.', 'With only one claim and no described mechanistic signals, there is nothing to compare for directional agreement. Consistency cannot be established from a single database entry.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'DIENOGEST is listed by Open Targets as an approved clinical-stage small molecule for endometriosis.', NULL, '{a6986c6d-9396-47dd-9760-ad2e4d3488c3}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:16.835698+00:00', '2026-06-16T18:04:16.835819+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('f3290c24-e092-4693-8722-ecd1dc4e1e36', 'c9e66c9d-9d97-4244-98f1-0061b47da1e0', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 0, 0, 0, 0, 'Only a single claim is provided, sourced from Open Targets, indicating INTERFERON ALFA is a Phase 1 clinical candidate for endometriosis. No mechanistic lines of evidence are described, so there is no convergence of independent mechanisms.', 'The claim is a database annotation of clinical stage rather than data from any mechanistic model (human, animal, or in-vitro). No experimental rigor can be assessed from this single registry-style statement.', 'The claim does not describe any specific molecular target or mechanism of interferon alfa action on endometriosis tissue. It merely states clinical candidate status without specifying the drug''s target engagement.', 'No target-phenotype relationship is described in the claim; it only references a Phase 1 designation. Without mechanistic detail there is no basis to assess fit between target and the endometriosis phenotype.', 'With only one non-mechanistic claim, there are no multiple mechanistic signals to compare for directional agreement. Consistency cannot be established.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Per an Open Targets database annotation, interferon alfa is listed as a Phase 1 clinical candidate for endometriosis.', NULL, '{f0ebb2a5-475f-4893-9895-afe8753575a7}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:17.369620+00:00', '2026-06-16T18:04:17.369641+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('aa5e31cb-b7c1-49c9-a5fb-e2039392c59a', 'ef8517a1-3e6a-4e8b-940d-e9d4dcb8a9f9', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 1, 1, 1, 'Only a single Open Targets database entry is provided, describing one mechanism of action (adenosine A2b receptor antagonism). No independent mechanistic lines converge; there is just one source and one claim.', 'The evidence is a curated database annotation indicating PHASE_3 clinical candidacy for endometriosis, which implies human-relevant context, but no actual study models, data, or outcomes are presented. The claim is a descriptive target/MOA mapping rather than experimental evidence.', 'The claim specifies a defined molecular target (adenosine A2b receptor antagonist), giving moderate specificity of action. However, pentoxifylline is a non-selective phosphodiesterase inhibitor with broad effects, so the single annotated target understates its pharmacology and limits confidence in specificity.', 'Adenosine A2b receptor signaling has links to inflammation, and endometriosis is an inflammatory condition, providing a plausible target-phenotype connection. However, the claim does not articulate how this target modulates the disease, so the fit is only weakly supported.', 'With only one claim there is no internal conflict, but also no multiple signals to confirm directional agreement. The single annotation is consistent with the proposed use but cannot establish convergence.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Per Open Targets, pentoxifylline is a Phase 3 clinical candidate for endometriosis acting as an adenosine A2b receptor antagonist.', 'Pentoxifylline may attenuate the inflammatory processes of endometriosis through antagonism of the adenosine A2b receptor.', '{22a8b94f-ea2a-41fc-a57b-075089c67575}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:24.106443+00:00', '2026-06-16T18:04:24.106473+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('45ac217d-c7ff-44f7-a791-10f249759c07', '417c1bfd-e910-49d5-9e17-fb7e399abf2d', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 0, 1, 1, 1, 'Only a single source (Open Targets) is cited, providing one annotation linking BENTAMAPIMOD to endometriosis via JNK inhibition. No independent mechanistic lines converge—there is just one drug-target-indication record.', 'The claim is a database annotation of clinical candidate status (Phase 2) with no described experimental model, human or otherwise. No data, study design, or mechanistic experiments are presented to assess model quality.', 'The claim names a specific target (mitogen-activated protein kinase 8 / JNK) and identifies BENTAMAPIMOD as a JNK inhibitor on that target. However, JNK has multiple isoforms and broad signaling roles, and the claim does not establish selectivity beyond the named annotation.', 'The claim asserts BENTAMAPIMOD is a Phase 2 clinical candidate for endometriosis acting via JNK inhibition, implying a target-phenotype link. But no mechanistic detail connecting JNK signaling to endometriosis pathology is provided to substantiate the fit beyond the database listing.', 'There is only one signal (a single Open Targets annotation), so there is no contradiction, but also no multiple signals to corroborate directionality. Consistency cannot be strongly affirmed with a single record.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'BENTAMAPIMOD is annotated as a Phase 2 clinical candidate for endometriosis acting as a JNK (MAPK8) inhibitor according to Open Targets.', 'BENTAMAPIMOD inhibits c-Jun N-terminal kinase (JNK/MAPK8), potentially modulating MAPK signaling implicated in endometriotic tissue growth.', '{e182b086-8d17-4588-92f7-88e2f6f1de4c}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:24.327598+00:00', '2026-06-16T18:04:24.327615+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('959c04d4-4d58-4855-bf79-3dec4385bc3e', '272ac39b-67c6-4415-8380-49a142741863', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 0, 0, 0, 0, 'Only a single database annotation from Open Targets links LACTULOSE to endometriosis, with no mechanistic detail or independent lines of evidence. No converging pathways, targets, or biological rationale are provided.', 'The sole claim is a database listing of unknown clinical stage with no underlying study, model, or experimental data. There is no human, animal, or in-vitro evidence cited.', 'No molecular target or mechanism of action is named for LACTULOSE in relation to endometriosis. The claim provides no information about specificity of drug action.', 'No target-phenotype relationship is described; LACTULOSE is an osmotic laxative with no stated mechanistic fit to endometriosis. The single database flag does not establish biological plausibility.', 'With only one annotation and no mechanistic signals, there is nothing to assess for directional agreement. No multiple signals exist to be consistent or inconsistent.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single Open Targets database annotation lists LACTULOSE as a clinical candidate for endometriosis at an unknown clinical stage, with no mechanistic or trial detail.', NULL, '{e2a17c07-cd70-4785-8ba8-dccc36b5a221}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:26.013404+00:00', '2026-06-16T18:04:26.013438+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('cdf34281-3e66-47b4-a5d7-894a0cb28138', '04feb95d-0eb2-47ce-8904-25fd0616941b', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 2, 2, 1, 'Only a single line of evidence is provided: an Open Targets annotation that elagolix sodium is a GnRH receptor antagonist approved for endometriosis. No independent mechanistic studies or converging pathways are cited.', 'The claim derives from a curated database (Open Targets) reflecting an approved clinical-stage drug, which implies human-relevant evidence, but no actual model, trial, or experimental data is shown to gauge strength or recency.', 'The claim explicitly names the drug''s mechanism as a Gonadotropin-releasing hormone receptor antagonist acting on the GnRH receptor target, indicating a well-defined and specific drug-target interaction.', 'GnRH receptor antagonism suppresses estrogen production, directly fitting the estrogen-dependent pathophysiology of endometriosis; the drug is listed at maximum clinical stage APPROVAL, supporting strong target-phenotype fit.', 'The single claim is internally consistent (antagonist mechanism appropriate for the condition), but with only one signal there is no opportunity to assess agreement across multiple mechanistic lines.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Elagolix sodium is an approved GnRH receptor antagonist indicated for endometriosis per Open Targets annotation.', 'By antagonizing the gonadotropin-releasing hormone receptor, elagolix suppresses gonadotropin and downstream estrogen production, reducing estrogen-driven endometriotic lesion activity.', '{784467bc-e6ba-4fc4-8418-6b9062bf19d1}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:26.678545+00:00', '2026-06-16T18:04:26.678576+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('08bd7da4-3e28-4129-9011-62e16d8a5716', 'c89c26d2-a9e5-42b2-b3bf-7b71ca24e957', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 2, 1, 1, 'Only a single line of evidence is present: an Open Targets database entry indicating ROSIGLITAZONE is a PPAR-gamma agonist clinical candidate for endometriosis. No independent mechanistic lines (in-vitro, animal, or human pathway studies) converge in the verified claims.', 'The claim derives from an Open Targets aggregation citing a PHASE_2 clinical stage for endometriosis, implying human-relevant context, but no actual study model, data, or results are provided. This is a database annotation rather than a primary mechanistic or clinical model, so rigor is limited.', 'The claim names a precise molecular target and mechanism: ROSIGLITAZONE acts as a PPAR-gamma agonist on peroxisome proliferator activated receptor gamma. This is a highly specific, well-defined drug-target action.', 'PPAR-gamma agonism has a recognized anti-inflammatory/anti-proliferative rationale potentially relevant to endometriotic lesions, and the PHASE_2 designation supports a plausible target-phenotype fit. However, the verified claim provides no direct evidence linking PPAR-gamma modulation to endometriosis pathophysiology, so fit is only moderately supported.', 'With only one claim there are no multiple mechanistic signals to compare; the single signal is internally coherent but provides no corroborating directionality. Consistency cannot be strongly established from a single database entry.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'ROSIGLITAZONE is a PPAR-gamma agonist listed as a Phase 2 clinical candidate for endometriosis per Open Targets.', 'ROSIGLITAZONE activates PPAR-gamma, which may exert anti-inflammatory and anti-proliferative effects relevant to endometriotic lesion growth.', '{596e0a9e-e2e2-4c60-91d0-97915396eaa5}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:35.380420+00:00', '2026-06-16T18:04:35.380488+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('86922073-4808-4e6c-b3a8-48b2838e2f2d', '7f4eee9f-14b2-4d55-984b-800d9658ce94', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 2, 1, 1, 'Only a single source (Open Targets) is cited, providing one line of evidence (drug-target-indication annotation). No independent mechanistic lines converge in the verified claims.', 'The claim reflects a clinical development annotation (PHASE_2 candidate for endometriosis), which implies human-relevant context, but no actual study data, model, or outcome is provided in the claims. The evidence is a database annotation rather than a reported experiment.', 'Tanezumab is described as a beta-nerve growth factor inhibitor acting on the specific target NGF, a highly specific monoclonal antibody mechanism. The drug-target relationship is clearly and precisely stated.', 'NGF inhibition is mechanistically relevant to pain pathways in endometriosis, supporting target-phenotype fit, and the drug is listed as a PHASE_2 endometriosis candidate. However, the claim provides only the annotation without phenotypic evidence linking NGF inhibition to endometriosis outcomes.', 'There is only one positive claim, so there are no conflicting signals, but also no convergence of multiple signals to assess directional consistency. The single annotation is internally coherent.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Tanezumab, an anti-NGF (beta-nerve growth factor) antibody, is annotated as a Phase 2 clinical candidate for endometriosis.', 'By inhibiting nerve growth factor (beta-NGF), tanezumab may reduce nociceptive sensitization and pain associated with endometriosis.', '{2d1651c0-2257-44d2-b01d-376a3cfae514}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:36.041063+00:00', '2026-06-16T18:04:36.041076+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('773f8570-5b6a-4e83-89a0-8c6913679cc4', '8db8c878-b6f6-4c3a-8916-67ca943ad4da', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 2, 1, 1, 'Only a single mechanistic line is provided — the Open Targets annotation that danazol acts as an androgen receptor agonist. No independent converging lines of evidence (e.g., gonadotropin suppression, anti-inflammatory effects) are cited.', 'The claim is a curated database annotation (Open Targets) linking an approved drug to endometriosis, not an experimental model. It reflects human-relevant clinical/regulatory context (APPROVAL stage) but provides no mechanistic study data.', 'The single claim names a specific drug action on a specific target: danazol as an androgen receptor agonist on the androgen receptor. The target-action relationship is explicitly stated.', 'Androgen receptor agonism is a plausible mechanism for endometriosis given danazol''s known clinical use, and the drug reached APPROVAL stage. However, the claim does not link AR agonism to an endometriosis-relevant phenotype mechanistically beyond the database association.', 'With only one claim there is no contradiction, but also no multiple signals to confirm directional agreement. The single annotation is internally consistent but cannot demonstrate convergence.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Danazol is an approved small molecule for endometriosis whose annotated mechanism of action is androgen receptor agonism.', 'Danazol acts as an androgen receptor agonist, which may contribute to its therapeutic effect in endometriosis.', '{386c2f50-98b1-4488-b898-1a8c09eddc1e}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:36.395931+00:00', '2026-06-16T18:04:36.395944+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('e8ba9b53-a6c8-4f99-840f-01baee018394', '8d5e712f-cc58-432d-a8d0-0c4a63b3ee9e', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 2, 2, 1, 'Only a single line of evidence is presented: the Open Targets database entry listing relugolix as a GnRH receptor antagonist clinical candidate for endometriosis. No independent mechanistic lines (e.g., separate PK, biomarker, or hormonal-axis studies) converge here.', 'The claim derives from a curated drug-target database citing Phase 3 clinical staging, which implies human-relevant development, but no actual study model, data, or outcomes are described. The evidence is a registry/database annotation rather than a primary mechanistic or clinical result.', 'The claim names a precise molecular action: relugolix is a Gonadotropin-releasing hormone receptor antagonist acting on the gonadotropin-releasing hormone receptor. This is a highly specific, single-target mechanism.', 'GnRH receptor antagonism suppresses the hypothalamic-pituitary-gonadal axis and estrogen production, which is a well-fitting mechanism for hormonally-driven endometriosis. The Phase 3 clinical stage for this indication reinforces target-phenotype fit.', 'With only one source, there is no opportunity for multiple signals to agree or conflict; the single mechanistic statement is internally coherent. Consistency cannot be strongly affirmed in the absence of corroborating independent claims.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Relugolix is a GnRH receptor antagonist in Phase 3 clinical development for endometriosis per Open Targets.', 'Relugolix antagonizes the GnRH receptor, suppressing the hypothalamic-pituitary-gonadal axis and reducing estrogen levels that drive endometriotic lesion growth.', '{89f027ce-7fd2-49a3-8b72-fd3d79b74b26}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:36.479915+00:00', '2026-06-16T18:04:36.479932+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('e71f2f7e-c822-4912-bed1-4f0d9b46cd79', 'fd1e03a2-ac14-4f25-a321-04f067467983', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 2, 2, 1, 'Only a single annotation line is provided (Open Targets target/MoA mapping). No independent mechanistic lines converge—just one database entry naming the progesterone receptor as target.', 'The claim derives from a curated drug-target database (Open Targets) referencing a Phase 2 clinical candidate, which is human-relevant but not an experimental mechanistic study. No primary data or model is presented.', 'Vilaprisan is explicitly characterized as a selective progesterone receptor modulator acting on the progesterone receptor, a well-defined molecular target.', 'Progesterone receptor modulation is a mechanistically coherent target for endometriosis, an estrogen/progesterone-responsive disease, and the candidate reached Phase 2 for this indication.', 'With only one claim there is no opportunity for signals to conflict, but also no convergent corroboration; direction is internally coherent but unsupported by additional evidence.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Vilaprisan is a Phase 2 clinical candidate for endometriosis acting as a selective progesterone receptor modulator on the progesterone receptor.', 'By modulating the progesterone receptor, vilaprisan may suppress endometrial proliferation and ectopic lesion growth in endometriosis.', '{798a3ae8-32e9-4a4e-99e2-ff6325fc5701}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:44.464989+00:00', '2026-06-16T18:04:44.465073+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('5b7ccc58-188f-4418-ba33-a8429e343b63', 'd0459f01-02b2-41b4-ac46-47d365868a7d', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 2, 2, 1, 'Only a single mechanistic line is presented: a database annotation that desogestrel is a progesterone receptor agonist candidate for endometriosis. No independent converging lines of evidence are cited.', 'The claim is sourced from Open Targets, a curated database, rather than from experimental human-relevant data. It reflects a clinical-candidate annotation with unknown clinical stage, giving only moderate, non-experimental support.', 'The mechanism is precisely defined: desogestrel acts as a progesterone receptor agonist on the progesterone receptor target, a specific named target-action pairing per Open Targets.', 'Progesterone receptor agonism is a well-established and mechanistically plausible target for endometriosis, an estrogen-driven progesterone-modulated condition. The target-phenotype fit is strong.', 'With only one claim and one mechanistic signal, the evidence is not internally contradictory but cannot demonstrate convergence across multiple signals. Consistency cannot be strongly established from a single source.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Desogestrel is annotated as a progesterone receptor agonist clinical candidate for endometriosis per Open Targets.', 'Desogestrel activates the progesterone receptor, which may suppress the estrogen-driven proliferation of endometrial tissue characteristic of endometriosis.', '{32e3943c-5978-4a6c-8647-9b28e9112d2b}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:45.904104+00:00', '2026-06-16T18:04:45.904128+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('a86cb761-0549-47bd-927d-9e6e4def12c2', 'a3c9739b-34d2-471b-b55a-67410e2f6672', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'other', 'pathway', 1, 1, 2, 1, 1, 'Only one line of mechanistic evidence is provided: a single Open Targets annotation stating that GONADOTROPIN, CHORIONIC acts as a luteinizing hormone/choriogonadotropin receptor agonist and is an early-phase clinical candidate for PCOS. There are no independent converging mechanistic sources.', 'The claim derives from a curated database annotation citing an EARLY_PHASE_1 clinical candidate status, which implies human-relevant context but provides no actual study data, model details, or trial outcomes. The evidence is a target-association record rather than a rigorous mechanistic study.', 'The mechanism of action is explicitly defined as a luteinizing hormone/choriogonadotropin receptor agonist acting on the named LH/CG receptor target, indicating high specificity of the drug''s action on a defined target.', 'LH/CG receptor agonism is mechanistically relevant to ovulation induction and ovarian function in PCOS, supporting target-phenotype fit. However, the single claim does not describe how this agonism translates to a PCOS phenotypic benefit, limiting the strength of the plausibility assessment.', 'With only a single mechanistic statement, there is no opportunity for multiple signals to align or conflict; the lone annotation is internally consistent but cannot demonstrate convergence.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'GONADOTROPIN, CHORIONIC is an early-phase (EARLY_PHASE_1) clinical candidate for PCOS acting as a luteinizing hormone/choriogonadotropin receptor agonist per Open Targets.', 'By agonizing the LH/choriogonadotropin receptor, chorionic gonadotropin may mimic the LH surge to support ovulation and ovarian function in PCOS.', '{5b152a96-e9ce-48aa-b470-eb240f724f92}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:47.987608+00:00', '2026-06-16T18:04:47.987668+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('07271e13-3eb3-4d6f-b179-d6d5870441c5', '376c48da-11ba-43a2-90c3-80220b6699a7', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'other', 'pathway', 0, 1, 2, 2, 1, 'Only a single line of evidence is present: an Open Targets annotation stating HISTRELIN is a GnRH receptor agonist clinical candidate for endometriosis. No independent mechanistic studies or convergent data lines are cited.', 'The claim derives from a curated database annotation (Open Targets) indicating maximum clinical stage of APPROVAL, which implies human-relevant clinical development, but no actual study models, data, or trial results are presented in the claims.', 'The mechanism is precisely specified: HISTRELIN acts as a gonadotropin-releasing hormone receptor agonist on the named target (gonadotropin releasing hormone receptor), a well-defined molecular action.', 'GnRH receptor agonism is a mechanistically well-established approach for endometriosis, suppressing gonadotropin/estrogen signaling that drives endometriotic lesion growth; the target-phenotype fit is strong and consistent with the APPROVAL stage noted.', 'There is only one mechanistic signal (the GnRH receptor agonist annotation), so directional agreement cannot be assessed across multiple lines, but the single claim is internally consistent with the named target and indication.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Open Targets annotates HISTRELIN as an approved-stage GnRH receptor agonist clinical candidate for endometriosis acting on the gonadotropin-releasing hormone receptor.', 'As a GnRH receptor agonist, histrelin causes downregulation of pituitary GnRH receptors, suppressing gonadotropin and ovarian estrogen production, thereby reducing estrogen-dependent endometriotic lesion activity.', '{47b87411-4acd-4afb-9a11-56d87d87d209}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:48.748658+00:00', '2026-06-16T18:04:48.748678+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('a2671b2c-0daf-4bcc-b7ea-16922cf2165c', 'b059b3fd-6222-499b-87bb-f6fd3d6cce63', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'other', 'pathway', 0, 1, 2, 1, 1, 'Only a single Open Targets database annotation is provided, listing ERGOCALCIFEROL as a VDR agonist clinical candidate for PCOS. No independent mechanistic lines converge; there is just one curated assertion.', 'The claim is a curated clinical-stage annotation (PHASE_2) rather than in-vitro data, suggesting human-relevant context, but no actual study, model, or outcome data are presented to assess rigor.', 'The mechanism is specified as a Vitamin D receptor agonist acting on the named target (vitamin D receptor), which is a precise drug-target relationship per the Open Targets annotation.', 'VDR agonism is a defined mechanism and the drug reached PHASE_2 for PCOS, implying some target-phenotype rationale, but no claim links VDR activation to a specific PCOS phenotype, so the fit is only partially supported.', 'There is only one mechanistic signal (VDR agonism), so nothing contradicts it, but with a single data point convergence cannot be demonstrated.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'ERGOCALCIFEROL is annotated as a vitamin D receptor agonist and a Phase 2 clinical candidate for PCOS per Open Targets.', 'Ergocalciferol activates the vitamin D receptor, which may modulate PCOS-related pathways.', '{86988982-3b1b-45ce-9d20-1d108fce93c0}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:54.678015+00:00', '2026-06-16T18:04:54.678066+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('0e1127c5-09c2-4d66-bda3-8735408f67d0', '7cdba395-c486-4218-80d1-e51cbece31cd', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'other', 'pathway', 0, 1, 2, 1, 1, 'Only a single line of evidence is present: an Open Targets database entry stating simvastatin is a Phase 3 clinical candidate for PCOS acting on HMG-CoA reductase. No independent mechanistic lines (e.g., separate biochemical, genetic, or animal studies) converge here.', 'The claim cites a clinical-stage designation (Phase 3) from Open Targets, which implies human-relevant testing, but no actual study data, model, or outcomes are provided. This is a database annotation rather than a recent mechanistic study, limiting rigor.', 'The drug''s action is specified precisely as HMG-CoA reductase inhibition on the target 3-hydroxy-3-methylglutaryl-CoA reductase, a well-defined molecular target. Simvastatin is a highly selective statin for this enzyme.', 'HMG-CoA reductase inhibition addresses the dyslipidemia and possibly hyperandrogenism components of PCOS, giving a partial target-phenotype fit. However, the claim itself provides no explicit mechanistic linkage between HMG-CoA reductase and PCOS pathophysiology.', 'With only one claim, there are no multiple mechanistic signals to assess for agreement. The single signal is internally coherent (clinical candidate with a defined target) but cannot demonstrate convergence.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Simvastatin is a Phase 3 clinical candidate for PCOS acting via inhibition of HMG-CoA reductase.', 'By inhibiting HMG-CoA reductase, simvastatin reduces cholesterol/steroidogenic substrate availability, potentially lowering androgen synthesis and improving the dyslipidemic profile of PCOS.', '{050d6b03-4c70-4a5e-9701-8c7982ce9aee}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:04:55.353259+00:00', '2026-06-16T18:04:55.353326+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
