29-680f-450b-8249-8342ad808801}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:05:50.795228+00:00', '2026-06-16T18:05:50.795243+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
