in (flagged for full text).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Per Open Targets, LEUPROLIDE is a Phase 1 clinical candidate for menopause acting as a gonadotropin-releasing hormone receptor agonist.', 'LEUPROLIDE acts as a GnRH receptor agonist, modulating the hypothalamic-pituitary-gonadal axis relevant to menopause-related hormonal changes.', '{4a0b12c6-2c69-4dff-be0e-84765beda878}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:06:01.061921+00:00', '2026-06-16T18:06:01.061999+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
