', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'EPELSIBAN is an oxytocin receptor antagonist that is a Phase 2 clinical candidate for adenomyosis per Open Targets.', 'By antagonizing the oxytocin receptor, EPELSIBAN may reduce uterine contractility and oxytocin-driven signaling implicated in adenomyosis.', '{4df7ccc9-d525-4c5d-97b2-ef8a1193a5ef}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:06:05.890962+00:00', '2026-06-16T18:06:05.900531+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
