INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('2ce05313-2c1f-48e9-b180-3978bbce0ae8', 'db706845-bfb7-495e-b4f6-c906a8b70148', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 1, 1, 2, 1, 1, 'The single source is a review (''Management of Menopausal Symptoms: A Review''), which provides one synthesis rather than independent replication. A single review scores 1, not higher.', 'The source is described as a narrative ''Review'' rather than an explicitly systematic review or meta-analysis with pooled effect estimates. Without evidence of meta-analytic rigor, this is scored as moderate (1).', 'The claim directly names estrogen (oral and transdermal) and addresses menopausal symptom management, so both the intervention and condition are explicitly identified.', 'The claim asserts comparable efficacy between oral and transdermal estrogen but provides no mechanistic detail or supporting data; the underlying estrogenic mechanism for menopausal symptom relief is plausible but not evidenced here.', 'Only a single source/claim is provided, so direction of effect cannot be compared across studies; per rule, a single source is scored 1 (n/a, not penalized).', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A review of menopausal symptom management states that oral and transdermal estrogen have similar efficacy.', NULL, '{722d5eaa-ab56-4302-97e0-5b861f322537}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:00.267885+00:00', '2026-06-16T18:09:00.267908+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('446face7-c41f-4d62-a035-17c78139c557', '0d5c4c37-eb3c-4a52-970a-a8788b4236d5', 'c4456f38-62e5-4add-a655-2ede20894c1f', 'efficacy', 'direct', 0, 1, 2, 1, 1, 'Only a single review source is cited, and the quote merely states bioidentical estrogens ''are available to treat vasomotor symptoms'' without presenting any underlying trial data. A single narrative statement provides no independent corroboration.', 'The source is described as a ''Review'' but the verified claim contains only an availability statement, not pooled trial data or a systematic meta-analysis. Without evidence of a structured evidence synthesis, this is scored as a low-rigor narrative claim.', 'Both the intervention (bioidentical estrogens) and the condition (vasomotor symptoms) are named directly in the claim and quote.', 'Estrogens are a mechanistically plausible treatment for menopausal vasomotor symptoms given estrogen deficiency underlies hot flashes, but the claim asserts availability rather than providing mechanistic evidence.', 'Only a single source/claim is provided, so directional consistency across studies cannot be assessed and is scored as n/a.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A review notes that bioidentical estrogens are available to treat vasomotor symptoms, but provides no quantitative efficacy data in the verified claim.', 'Estrogen replacement addresses the estrogen deficiency that drives menopausal vasomotor symptoms.', '{26ff456f-db8e-46b2-a634-8f99051767b3}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:03.939080+00:00', '2026-06-16T18:09:03.939106+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('573f38af-d562-41e9-8939-1bfb1fa7b989', '93a34c5d-3ebd-4881-a33a-f573405ce591', '606f4ef4-4f46-4762-ac37-2701c811083f', 'safety', 'direct', 1, 1, 2, 1, 1, 'Evidence comes from a single source, a review article (''Management of Menopausal Symptoms: A Review''). Only one synthesis/source is cited with no independent corroboration, warranting a score of 1 at most.', 'The source is a narrative review reporting incidence rates, but no specific RCT or meta-analysis design is identified for this claim. Without a clearly identified well-powered RCT or formal meta-analysis, this scores as observational/review-level evidence.', 'The claim directly names both the intervention (low-dose CEE plus bazedoxifene) and the condition (breast cancer). The comparison to placebo with breast cancer incidence rates is explicit.', 'The claim provides quantitative incidence data (0.25%/year vs 0.23%/year) supporting safety, but no mechanism explaining why this combination would not increase breast cancer risk is articulated. The bazedoxifene SERM component plausibly counteracts estrogenic breast stimulation, but this mechanism is not stated.', 'Only a single source/claim is presented, so directional agreement across studies cannot be assessed. Per the single-study rule, this is scored 1 (not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Low-dose conjugated estrogen plus bazedoxifene showed breast cancer incidence comparable to placebo (0.25%/year vs 0.23%/year), suggesting no increased risk.', 'The bazedoxifene SERM component may oppose estrogen-driven breast tissue proliferation, offsetting the estrogenic component''s potential to increase breast cancer risk.', '{7cbb4d05-7251-4b5e-a61a-eba5094ad83a}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:06.304546+00:00', '2026-06-16T18:09:06.304573+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('baaa9f2f-8128-41e4-b4da-2ecfc398b2d4', 'ef42fd4c-c6b7-4147-ba81-f23ca6189dd4', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'direct', 1, 2, 2, 1, 1, 'The single source is a review (''Management of Menopausal Symptoms: A Review.''), which counts as one synthesis rather than independent replication. No additional independent studies are presented, so this caps at 1.', 'The evidence is drawn from a review article synthesizing menopausal hormone therapy safety data, and the quantified excess risk estimate (1 excess event/1000 person-years) reflects pooled/RCT-derived data typical of WHI-type trials. A review/meta-analysis level source justifies a rigor score of 2.', 'The claim names CEE plus MPA explicitly and addresses breast cancer risk in the context of menopausal symptom management. Both the specific intervention and the menopause context are directly identified.', 'The claim asserts an association between combined estrogen-progestin therapy and breast cancer without detailing a specific mechanism in the quote. The hormonal stimulation mechanism is biologically plausible but not evidenced within the provided claim text.', 'Only a single claim from a single source is provided, so directional agreement across multiple studies cannot be assessed. Per the n/a rule for a single source, this is scored 1.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Combined CEE plus MPA therapy in menopausal women is associated with an increased breast cancer risk of approximately 1 excess event per 1000 person-years compared with placebo.', NULL, '{73aff0d5-0c86-46bc-8b7a-1438aa138a04}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:08.969238+00:00', '2026-06-16T18:09:08.969278+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
