s for women with bothersome vasomotor symptoms.', NULL, '{7bfc4c4e-e20f-4bbd-8bea-d39a9623612a}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:11.161800+00:00', '2026-06-16T18:09:11.161830+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
