4387-9c1c-36bc801d1b58}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:38.767955+00:00', '2026-06-16T18:09:38.767989+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('b1777fa2-d3d0-4bf4-a94a-78665965fbaf', 'db706845-bfb7-495e-b4f6-c906a8b70148', 'd3e225fc-d859-4953-a7bf-9788fac4b5d7', 'efficacy', 'direct', 1, 1, 2, 1, 1, 'The single source is a review (''Management of Menopausal Symptoms: A Review'') making a general first-line therapy statement. A single synthesis is not independent replication, and no consistent independent studies are cited, so it scores 1.', 'The source is a narrative-style review asserting first-line status rather than a quantified meta-analysis or specific RCT data. No trial design, effect estimates, or pooled analysis are provided in the claim, supporting a mid-level rigor score.', 'The claim directly names both estrogen and GSM (''Hormonal therapy with estrogen is the first-line therapy for ... GSM symptoms''). Both the intervention and condition are explicitly stated.', 'Estrogen acting on estrogen-responsive genitourinary tissue is a well-established plausible mechanism, but the claim only asserts efficacy without describing or evidencing the mechanism. Hence a plausible-but-not-evidenced score.', 'Only a single source is provided, so directional agreement across studies cannot be assessed and is scored neutrally per the n/a convention.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A review identifies estrogen hormonal therapy as the first-line treatment for genitourinary syndrome of menopause symptoms.', 'Estrogen restores estrogen-dependent genitourinary tissue, relieving GSM symptoms.', '{1b24d5aa-9a70-49da-bb0c-ea725d4ca9e5}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:40.197129+00:00', '2026-06-16T18:09:40.197151+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('32358926-24a7-4cb0-bce8-1662b4f0f60b', 'ac3177b4-dd91-445b-bb43-15769c481a42', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 1, 1, 2, 1, 1, 'Evidence comes from a single review article (''Management of Menopausal Symptoms: A Review''), which counts as one synthesis rather than independent replication. Only one source is cited and it offers a general statement, not multiple independent studies.', 'The single source is a narrative review summarizing that nonhormonal medications can be effective, but no underlying RCT or meta-analysis design is documented in the claims. Without explicit trial-level detail, this scores as an observational/review-level statement.', 'Both the intervention (paroxetine) and the condition (menopause symptoms) are explicitly named in the verbatim quote, satisfying direct specificity.', 'The claim asserts paroxetine ''can be effective'' for menopausal symptoms but provides no mechanistic detail in the quote. SSRIs reducing vasomotor symptoms is a plausible mechanism but is not evidenced here.', 'Only a single source is provided, so directional agreement across studies cannot be assessed; per rules this defaults to 1 (not penalized).', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A review states that nonhormonal medications including paroxetine can be effective for menopausal symptoms.', NULL, '{41c05ed3-2e56-4709-a84c-daf8b190eb70}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:43.917394+00:00', '2026-06-16T18:09:43.917417+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('46e3574e-15b2-4996-aeed-075aa6d2d28f', '6dec39ef-5927-490f-8183-89340da7d9d1', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 1, 1, 2, 1, 1, 'Evidence comes from a single review source (''Management of Menopausal Symptoms: A Review''), which counts as one synthesis and is not independent replication. No multiple independent studies or large RCT is cited.', 'The source is a narrative-style review stating venlafaxine ''can be effective,'' without details of an RCT or formal meta-analysis design. Absent evidence of systematic methodology, this scores as observational/low-rigor level.', 'The claim names venlafaxine directly and menopause/menopausal symptoms directly. Both the intervention and condition are explicitly identified.', 'Venlafaxine as a nonhormonal medication for menopausal (vasomotor) symptoms reflects an accepted plausible mechanism, but no specific mechanistic detail is given in the claim. Thus mechanism is plausible but not evidenced here.', 'Only a single source/claim is provided, so directional agreement across studies cannot be assessed. Per rules, a single source is scored neutrally rather than penalized.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A review states that nonhormonal medications including venlafaxine can be effective for menopausal symptoms.', 'As an SNRI, venlafaxine may reduce vasomotor menopausal symptoms via serotonergic/noradrenergic modulation of thermoregulation.', '{bc7d0a46-7815-47a6-8b2e-59645b0ebcda}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:45.315734+00:00', '2026-06-16T18:09:45.315761+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('aefcba19-7af9-4c2b-85e1-4e860682bd89', 'c8862c5e-527a-4425-bb68-7d098915f79d', 'c4456f38-62e5-4add-a655-2ede20894c1f', 'efficacy', 'direct', 0, 0, 2, 1, 1, 'Only a single source is provided (a clinical narrative/review titled ''Managing menopause after cancer''), and it makes only a general efficacy assertion without citing independent studies. A single source with an unspecified, non-systematic design scores at the bottom of the range.', 'The single claim is a bare assertion of efficacy with no described study design, sample, or quantitative outcome. There is no evidence it derives from an RCT, meta-analysis, or active guideline, so it defaults to the lowest rigor tier.', 'The claim names both the intervention (menopausal hormone therapy) and the condition (vasomotor symptoms) directly. Both are explicitly stated in the verbatim quote.', 'Menopausal hormone therapy plausibly relieves vasomotor symptoms by replacing declining estrogen, a well-accepted mechanism, but the quote itself asserts efficacy without describing or evidencing any mechanism. This warrants a plausible-but-not-evidenced score.', 'Only a single source is provided, so directional agreement across studies cannot be assessed. Per the n/a rule, a single source is scored 1 without penalty.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single clinical source asserts that menopausal hormone therapy is an effective treatment for vasomotor symptoms.', 'Replacement of declining estrogen restores hypothalamic thermoregulatory control, reducing vasomotor symptoms.', '{a48b6bbc-f628-4fc2-b706-de818edba12f}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:47.062047+00:00', '2026-06-16T18:09:47.062069+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('eb6a8844-c0d7-4328-a114-534607a2e201', 'c8862c5e-527a-4425-bb68-7d098915f79d', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'direct', 2, 2, 2, 1, 1, 'Multiple independent syntheses converge: a systematic review/meta-analysis of MHT cardiovascular safety (claims 2-7) and an umbrella review pooling 17-23 trials with tens of thousands of women (claims 8-14) plus a cancer-population source (claim 1). The consistent stroke/VTE harm signal across distinct reviews with large samples (37,272 and 42,292 women) supports strong corroboration.', 'Evidence derives from a systematic review and meta-analysis (claims 2-7) and an umbrella review of randomized trials (claims 8-14), the highest design tiers. Effect estimates with confidence intervals from pooled RCT data confirm meta-analytic rigor.', 'Both menopausal hormone therapy and the postmenopausal/menopause population are named directly throughout (e.g., ''MHT and placebo... in postmenopausal women'', claim 3). Drug and condition are unambiguously matched.', 'The claims report empirical harm signals (increased stroke and VTE risk) but do not articulate the underlying mechanism (e.g., estrogen-driven procoagulant effects). Mechanism is plausible given known hormone effects on coagulation but is not stated or evidenced in the quotes.', 'Two independent reviews agree on direction: MHT increases stroke risk (claim 4: ''increases the risk of stroke''; claim 8: RR 1.17, 95% CI 1.05-1.29) and venous thrombosis/VTE risk (claims 5, 9). Findings are concordant across sources for the principal harms.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Strong', true, 1, NULL, false, 'abstract', 'Meta-analytic and umbrella-review evidence in postmenopausal women shows menopausal hormone therapy increases the risk of stroke (RR ~1.17) and venous thromboembolism while showing no significant difference in all-cause mortality.', NULL, '{df16f77b-787c-4ccc-a23e-6d18e0eaf458,40e53110-c5d6-45cc-bc47-916d65f4dbbb,880a36ca-8735-4e98-b010-6d621229a9fd,9192a1a3-b2ff-45ff-a679-f689d1ffa5a8,d1b85c7e-1a4a-4e31-89de-fb2142c27f63,d2c622ee-0427-4640-a233-e41a0e46c6b2,0a427f9a-5e00-44e3-bf36-fac1320cc7fe,d159feb2-17a9-4df9-a4a8-c987fcecbd08,5c50924f-40f0-4f83-bcf4-4a161152e172,8757cf1c-713d-4bb2-ad42-f8c09236b9d6,8f1e2f24-46e1-472e-bd8e-d7946b6c1ec4,f0bd2eb9-4090-4c53-9bf0-4dcbc5a26eb0,8509fbb5-9987-4170-a3c1-9cb8dc8ca763,f93c03ca-f726-41d2-b928-7947fa9e9712}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:51.361681+00:00', '2026-06-16T18:09:51.361707+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('9e620d71-7fa6-4167-957f-7b903be27050', '6b17bb13-df34-4d1b-ad99-57fda1af222e', 'b598a5c0-7c94-4cd1-b929-4e5efbb0d0ff', 'safety', 'direct', 0, 1, 2, 0, 1, 'Only a single source (''Managing menopause after cancer'') provides one general safety statement. There is no independent corroboration and no indication this is a systematic review or RCT, so it scores at the bottom.', 'The claim is a narrative safety assertion (''seems safe for most patients'') from what appears to be a review/guidance article rather than a quantified RCT or meta-analysis. The hedged language and lack of design detail support a mid-low rigor score.', 'Both the intervention (vaginal oestrogen) and the condition (genitourinary symptoms) are named directly in the claim and quote.', 'No mechanism for the safety profile is described in the claim; only a general statement of safety is given. No biological rationale is asserted or evidenced.', 'There is only a single claim from a single source, so directional consistency cannot be assessed and is scored neutral per convention.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single source states that vaginal oestrogen seems safe for most patients with genitourinary symptoms.', NULL, '{03576765-7ee3-40b0-bb1d-3c679095f37f}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:51.678225+00:00', '2026-06-16T18:09:51.678252+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('7fd2a119-5962-4b70-abba-80298a7988b7', 'cb5f6b9c-2043-4026-ace6-cdba829e4bc0', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 0, 0, 1, 0, 1, 'Only a single source (''Managing menopause after cancer.'') is cited, and it merely asserts ''emerging evidence'' without describing study design or independent replication. A single, vaguely-worded source scores at the bottom of the range.', 'The claim only states that ''emerging evidence supports the efficacy'' with no described study design, sample, or methodology. There is no indication of an RCT, meta-analysis, or even an observational study, so it defaults to the lowest tier.', 'Menopause is named directly, but the intervention is a broad umbrella (''non-pharmacological and non-hormonal treatments'') rather than a specific named therapy. The lack of a concretely identified intervention limits specificity.', 'No mechanism of action is described in the claim; it only asserts efficacy in the context of contraindicated hormone therapy. Without any mechanistic statement, plausibility cannot be credited.', 'Only one source and one claim are provided, so directional agreement across studies cannot be assessed. Per the single-study rule, this is scored neutrally at 1.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single source asserts that emerging evidence supports the efficacy of non-pharmacological and non-hormonal treatments for menopause when hormone therapy is contraindicated or avoided.', NULL, '{4af33a29-a46a-41c7-8fd0-52920dfe742a}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:54.943962+00:00', '2026-06-16T18:09:54.943992+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('39e006eb-4475-4dc2-9bc5-808fc11000ae', 'e7625ebb-ef58-4544-83c2-8fadd23058a0', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 1, 2, 2, 1, 1, 'The evidence comes from a single systematic review and meta-analysis. Per scoring rules, a single synthesis scores 1 and does not constitute independent replication.', 'The source is a systematic review and meta-analysis, which qualifies as the highest design tier (score 2).', 'The claim names both menopause hormone therapy (MHT) and menopause-related symptoms directly, so both drug and condition are explicitly identified.', 'The claim asserts MHT alleviates menopause-related symptoms but provides no explicit mechanistic detail in the quote. A plausible hormonal mechanism is implied but not evidenced here, so a plausible-but-unevidenced score of 1 applies.', 'Only a single source/claim is provided, so directional consistency across studies cannot be assessed and is scored as n/a (1).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis describes menopause hormone therapy as an effective method to alleviate menopause-related symptoms in women.', NULL, '{5573a4d7-5018-4fa3-b0d5-a7c4e8bd5f90}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:57.697124+00:00', '2026-06-16T18:09:57.697153+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('ef0ab4ad-c2b7-4f58-93bd-4eebf1dccb55', 'e7625ebb-ef58-4544-83c2-8fadd23058a0', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'direct', 1, 2, 2, 0, 1, 'The evidence derives from a single systematic review and meta-analysis, which counts as one synthesis rather than independent replication. Per scoring rules, a single review scores at most 1.', 'The source is a systematic review and meta-analysis, which qualifies for the highest rigor tier. However, the claim only conveys uncertainty rather than a definitive safety finding.', 'The claim names both menopause hormone therapy (MHT) and the relevant population (postmenopausal women) directly, addressing cardiovascular safety. Both intervention and condition context are explicit.', 'The single claim asserts uncertainty about benefits and risks without describing any mechanism by which MHT affects the cardiovascular system. No mechanistic pathway is stated or evidenced.', 'Only a single source is provided, so directional agreement across studies cannot be assessed. Per rules, a single source defaults to 1.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis found that the cardiovascular benefits and risks of menopause hormone therapy in postmenopausal women remain unclear.', NULL, '{3a364fbc-964b-41f4-bfe7-4a9863f8213a}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:09:58.857077+00:00', '2026-06-16T18:09:58.857107+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('1d8adce2-9e2d-4023-a493-004560777170', 'b1453211-e2fd-4ca7-8c55-3c5844685c10', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'Evidence comes from a single systematic review and meta-analysis, which counts as one synthesis and is not independent replication. Per scoring rules a single meta-analysis scores 1.', 'The source is a systematic review and meta-analysis, which is a high-rigor design scoring 2.', 'The claim directly names estrogen and progesterone combination therapy and addresses postmenopausal women / menopause hormone therapy, so both intervention and condition are explicitly identified.', 'The claim only reports an outcome comparison (no difference vs mono-estrogen therapy) without asserting or evidencing any mechanism. No mechanistic explanation is provided in the verified claim.', 'Only a single source/claim is provided, so direction of effect cannot be cross-compared across independent studies. Per rules a single study is scored 1 (n/a, not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis in postmenopausal women found that combined estrogen-progesterone therapy did not alter cardiovascular endpoint outcomes compared with estrogen-only therapy.', NULL, '{4252da26-d0b4-4d95-9295-73515da10e3b}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:01.619463+00:00', '2026-06-16T18:10:01.619501+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('b1910822-d605-454e-9b89-bd93675c64b0', 'dc7af29e-ac43-4db0-b14e-f9ba729cd9b9', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'other', 'direct', 1, 2, 2, 0, 1, 'The evidence comes from a single systematic review and meta-analysis comparing mono-estrogen therapy to combination therapy for cardiovascular endpoints. A single synthesis does not constitute independent replication, so it scores 1 rather than 2.', 'The source is explicitly a systematic review and meta-analysis, which qualifies for the highest rigor tier. This design supports a score of 2.', 'The claim names mono-estrogen therapy directly and concerns postmenopausal women (menopause). Both the intervention and the condition are explicitly stated.', 'The claim reports a comparative outcome on cardiovascular endpoints but offers no mechanism explaining why estrogen monotherapy would or would not differ from combination therapy. No mechanistic basis is asserted or evidenced.', 'Only a single pooled source is provided, with no separate independent studies to compare directional agreement. Per the single-source rule, consistency is scored 1 (n/a, not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis found no difference in cardiovascular endpoints between estrogen monotherapy and estrogen-progesterone combination therapy in postmenopausal women.', NULL, '{319df9be-a100-45aa-9521-09357801d8ee}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:04.878244+00:00', '2026-06-16T18:10:04.878287+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('5371a279-9e66-47d2-ac62-32c26fd9ee7c', 'c8862c5e-527a-4425-bb68-7d098915f79d', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 1, 2, 2, 2, 1, 'Evidence comes from two syntheses: a systematic review/meta-analysis on cardiovascular outcomes and an umbrella review on broader women''s health outcomes. While these are two separate reviews, they largely pool overlapping trials and represent syntheses rather than independent low-bias RCTs; a single or pair of reviews does not constitute three+ genuinely independent primary studies.', 'Both sources are meta-analyses/umbrella reviews of randomized trials (e.g., ''frequency: 9 trials, 1,104 women, RR 0.43'' and ''all fracture (30 trials, 43,188 women)''), which is the highest design tier.', 'Both the intervention (menopausal hormone therapy) and the population/condition (postmenopausal women, menopause/vasomotor symptoms) are named directly, e.g., ''MHT was beneficial for vasomotor symptoms'' and ''in postmenopausal women.''', 'Mechanism is evidenced via the improvement in flow-mediated arterial dilation (''MHT could improve flow-mediated arterial dilation (FMD) (SMD = 1.46)'') indicating endothelial function effects, alongside fracture and vasomotor benefits consistent with estrogen biology.', 'Multiple outcomes across both reviews agree in direction favoring benefit (vasomotor symptoms, fracture, FMD), and the timing-hypothesis findings are internally consistent (earlier MHT yields better FMD and lower CV events). Some null cardiovascular endpoints (NMD, all-cause death overall) reflect outcome specificity rather than contradictory direction.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Strong', true, 1, NULL, false, 'abstract', 'Meta-analytic evidence indicates MHT reduces vasomotor symptom frequency and severity and fracture risk, and improves flow-mediated arterial dilation in postmenopausal women, with greater benefit when started within 10 years of menopause.', 'Estrogen improves endothelial function (increased flow-mediated dilation) and bone density, accounting for cardiovascular and fracture benefits, particularly when initiated early after menopause.', '{5abacb13-a7d9-40fa-a1e3-4df8e1e0ed8b,318180b4-c927-48cd-97c3-368ce4ef7a41,eecea4ab-c2e3-4472-86af-1f2875a9d5d9,ac7bef10-d05d-43c5-8b7a-18ccba01e679,0cde33f9-28b4-4836-8c3d-adef4e323f5d,bee69e21-b05d-4ad7-bbda-ada501e3082c,0bd9d634-5f5f-4012-8854-e6cc89322453,47d4bb35-11ec-4a8a-b933-625f7bde2aa3,1bfbb07f-db53-4033-a6d4-f0d00c51e53f,f18eb92c-efb3-4111-892c-563c64f2dfe7,ae3436c3-cc00-4d71-b981-ac470a0d1e48,28edada1-1c1f-4f02-a3bc-d7676d87ef34,1e7f59f4-b24f-48eb-8a20-8ec84ba8defa,40b9ae3f-029d-4735-a8f1-3006132d7b01,2b587d95-8f5e-40ea-af4c-af0797a731f3,5bf063b3-7c2d-4bb8-83f1-7f5bd89699a1,72ab202f-259c-46fe-b78d-9c7a10650195,5217b94f-a965-41ad-9f29-cf5bbc5672f7}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:05.026969+00:00', '2026-06-16T18:10:05.026996+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('da05bb0a-3bad-4caf-a85d-af3950329fec', 'c8862c5e-527a-4425-bb68-7d098915f79d', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'other', 'direct', 1, 2, 2, 0, 1, 'The single source is an umbrella review (a synthesis of reviews), which counts as one non-independent synthesis rather than multiple independent studies. Per scoring rules a single systematic review/meta-analysis scores 1, not 2.', 'The source is an umbrella review (''Menopausal hormone therapy and women''s health: An umbrella review''), which is a high-level synthesis qualifying for the meta-analysis/review tier. This warrants a rigor score of 2.', 'The claim directly names MHT (menopausal hormone therapy) and concerns women''s health/menopausal context. Both the intervention and the condition population are explicitly identified.', 'The claim only states a ''complex balance of benefits and harms'' without articulating any mechanism. No biological pathway is asserted or evidenced.', 'Only a single source is provided, and the claim itself notes a complex balance of benefits and harms rather than a clear directional agreement. With one source, consistency defaults to 1 (not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', true, 1, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'An umbrella review concludes that menopausal hormone therapy has a complex balance of benefits and harms across multiple women''s health outcomes.', NULL, '{22b8c4a5-84e3-44aa-93ad-9145009b1b77}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:06.002763+00:00', '2026-06-16T18:10:06.002792+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('2453ee82-5269-43cf-a4e5-3ea01cdec5dd', 'b2cbbb8a-395f-49c0-b7c9-3eda89015834', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 0, 1, 0, 1, 'Only a single source is provided, and it is a narrative/state-of-the-science review rather than independent replicated evidence. The claim itself emphasizes a lack of rigorous RCTs, so there is no corroboration of any treatment effect.', 'The single claim is a narrative review explicitly noting the absence of rigorous large RCTs. It provides no controlled trial or meta-analytic outcome data, so rigor is minimal.', 'The condition vulvodynia is named directly, but the intervention is only ''various treatments''/''most treatment methods'' with no specific drug identified. This prevents a clean drug+condition match.', 'No mechanism of action is asserted or evidenced in the claim; it merely states efficacy cannot be determined. No biological pathway is described.', 'Only a single source is available, so directional consistency cannot be assessed and is not penalized. The claim does not report comparable outcome directions across studies.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A state-of-the-science review concludes that the efficacy of most vulvodynia treatments cannot be determined due to a lack of rigorous, large RCTs.', NULL, '{198ed0ba-a402-4970-ae7e-d16a0164de46}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:09.956555+00:00', '2026-06-16T18:10:09.956582+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('339d7def-48a0-4399-a4cc-5fc9f8f65ddb', 'a3fe58b5-92c9-410f-bb0c-a71c90fcb81c', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 0, 2, 0, 1, 'All claims derive from a single source, a case series of 20 patients. A single primary study scores 0, and there is no independent replication present.', 'The evidence is a case series (claim 1 source explicitly ''a case series of 20 patients''), an uncontrolled observational design with no comparator, placing it at the lowest rigor tier.', 'Both the drug (amitriptyline) and the condition (vulvodynia) are named directly in claims 1-3, satisfying full specificity.', 'The claims assert pain relief but provide no mechanistic explanation for how amitriptyline acts on vulvodynia. No mechanism is described, so plausibility is only asserted at best.', 'Only a single study is available, so directional consistency cannot be assessed and the default n/a score of 1 applies.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, 'small sample (N≈20); corroboration/rigor capped at 1', false, 'abstract', 'A single case series of 20 patients suggests amitriptyline may provide pain relief and quality-of-life improvement in vulvodynia associated with vulvar lichen sclerosus.', NULL, '{672826eb-9e88-4f2a-b9ae-0afef69a6bad,c5858179-99ba-47ae-b48a-a064c00fcaf3,64dc8c6f-4ca5-449b-b73e-08854f7f2add}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:11.619979+00:00', '2026-06-16T18:10:11.620010+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('78034276-e6c3-4237-b831-3fe5fc0c256f', 'a3fe58b5-92c9-410f-bb0c-a71c90fcb81c', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'safety', 'direct', 0, 0, 2, 0, 1, 'Evidence rests on a single case series of 20 patients, which is one primary source with no independent corroboration. A single uncontrolled case series scores 0 for corroboration.', 'The source is a case series, the lowest tier of clinical study design with no control group or randomization. This warrants a rigor score of 0.', 'The source explicitly names amitriptyline and vulvodynia (in patients with vulvar lichen sclerosus), satisfying both the drug and condition being directly named.', 'The claim only asserts that ''adverse effects need to be carefully managed'' without describing any mechanism for the adverse effects. No mechanistic basis is provided.', 'Only a single source is provided, so directional agreement across studies cannot be assessed and the dimension is treated as n/a, scored 1.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, 'small sample (N≈20); corroboration/rigor capped at 1', false, 'abstract', 'A single case series of 20 patients with vulvodynia treated with amitriptyline indicates that adverse effects require careful management.', NULL, '{9d97042c-68f4-46bd-8edc-4d714400ed4d}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:11.750247+00:00', '2026-06-16T18:10:11.750279+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('18f3ddac-c9b5-44c5-9995-4136b90f2aff', 'c46a843c-320f-4984-8b4c-c0d7292b3ba8', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 2, 2, 0, 1, 'The single claim references ''at least one RCT or comparative effectiveness trial'' for the desipramine+lidocaine combination, drawn from one review/state-of-science article. This is a single source citing at least one trial, not multiple independent corroborating studies. No replication is demonstrated.', 'The claim states the combination had ''the highest level of evidence with at least one RCT or comparative effectiveness trial,'' indicating RCT-level design. The supporting source is a state-of-science review. RCT/meta-analysis-level rigor is asserted.', 'Both the intervention (oral desipramine with 5% lidocaine cream) and the condition (vulvodynia) are named directly in the claim and quote. The combination is explicitly identified.', 'No mechanism is described in the claims for how desipramine plus lidocaine cream works on vulvodynia. The quote only addresses level of evidence, not pharmacologic action. Mechanism is not even asserted.', 'Only a single source/claim is provided, so directional agreement across studies cannot be assessed. Per the n/a rule for a single study, this defaults to 1. No conflicting findings are presented.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A state-of-science review reports that oral desipramine with 5% lidocaine cream has the highest level of evidence (at least one RCT or comparative effectiveness trial) among vulvodynia treatments.', NULL, '{82a86cab-6982-4358-87fa-6bebebb43df6}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:14.603949+00:00', '2026-06-16T18:10:14.603976+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('13dc8d3d-053a-4eb9-b9d4-0ed430f59589', '00191cf4-30f9-42f2-a32a-56b660dfb924', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'The single source is a review describing that this combination had ''at least one RCT or comparative effectiveness trial,'' indicating one underlying trial rather than multiple independent replications. This does not meet the threshold for independent corroboration or a single large low-bias RCT.', 'The claim states the evidence base includes at least one RCT or comparative effectiveness trial for this combination, which qualifies as RCT-level design. However the actual trial details (N, effect size) are not provided in the claim.', 'Both the intervention (intravaginal diazepam tablets with intravaginal TENS) and the condition (vulvodynia) are named directly in the verified claim.', 'No mechanism is described in the claim; it only asserts a level of evidence. Neither a plausible nor evidenced mechanistic pathway is articulated.', 'Only a single source describing a single trial is referenced, so directional consistency across studies cannot be assessed. Per scoring rules, a single study defaults to 1.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A state-of-the-science review reports that intravaginal diazepam plus intravaginal TENS has at least one RCT or comparative effectiveness trial supporting its use for vulvodynia, placing it among the highest-evidence treatments.', NULL, '{567fb8cb-f23f-44ae-babb-73faa7bc6c71}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:17.913644+00:00', '2026-06-16T18:10:17.913671+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('6ac03bce-e0a2-4814-8dff-f9571101ae11', '536345b3-2446-4fef-b837-c3a232636a4e', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'The evidence derives from a single review-type source (''State of the Science'') that notes at least one RCT or comparative trial exists for enoxaparin in vulvodynia. This is a single synthesis referencing one trial, not independent replication, so it cannot exceed 1.', 'The claim states enoxaparin had the highest level of evidence with at least one RCT or comparative effectiveness trial for vulvodynia, indicating an RCT-level design. RCT/comparative trial evidence supports a score of 2.', 'Both the intervention (enoxaparin sodium subcutaneous injections) and the condition (vulvodynia) are explicitly named in the quote. This is a direct, specific match.', 'The verified claim describes only the level of evidence; it does not assert or explain any mechanism by which enoxaparin would affect vulvodynia. No mechanistic information is provided.', 'Only a single source describing a single trial is available, so directional agreement across studies cannot be assessed. Per the n/a rule, this defaults to 1.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A State-of-the-Science review reports that enoxaparin sodium subcutaneous injections have at least one RCT or comparative effectiveness trial supporting their use for vulvodynia.', NULL, '{74c74285-4100-4dd0-8e38-f1554050ba8c}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:19.318565+00:00', '2026-06-16T18:10:19.318587+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('ad375b21-75de-4c4b-8f3d-e738d45f2960', '9f6b79eb-b8e7-49b9-bdd4-2a8644fa3edb', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'The single claim derives from one review/state-of-the-science article that summarizes the existence of at least one RCT, not multiple independent corroborating studies presented here. This counts as a single synthesis source (score 1), not independent replication.', 'The claim references that botulinum toxin type A 50 units ''had the highest level of evidence with at least one RCT or comparative effectiveness trial,'' indicating RCT-level design. This qualifies for the highest rigor tier despite being relayed via a review.', 'Both the intervention (botulinum toxin type A 50 units) and the condition (vulvodynia) are explicitly named in the quote. The claim directly concerns this drug acting on this condition.', 'The claim only states a level-of-evidence ranking and does not assert or describe any mechanism by which botulinum toxin type A acts on vulvodynia. No mechanistic content is provided.', 'Only a single source/claim is provided, so directional agreement across studies cannot be assessed. Per the n/a rule, this defaults to 1 without penalty.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A state-of-the-science review notes that botulinum toxin type A 50 units for vulvodynia is supported by at least one RCT or comparative effectiveness trial, giving it the highest level of evidence among reviewed treatments.', NULL, '{5edd2d27-0929-471e-933d-1f582e053c12}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:20.134425+00:00', '2026-06-16T18:10:20.134450+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('09100a76-3c70-42f6-98c7-be63bdabdbb9', 'f53b5b6c-b533-4e5b-8838-2496fce31b8d', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'The single source is a review-type synthesis (''State of the Science'') noting at least one RCT or comparative effectiveness trial supports intravaginal TENS. A single synthesis without independent replication detail scores 1, not 2.', 'The claim references at least one RCT or comparative effectiveness trial supporting intravaginal TENS, and the source is a state-of-the-science review citing this highest level of evidence. RCT-level design warrants a 2.', 'Both the intervention (intravaginal TENS as a single therapy) and the condition (vulvodynia) are named directly in the claim and quote.', 'No mechanism for how intravaginal TENS produces its effect is asserted or evidenced in the claim; only the level of evidence is described. Without any stated mechanism, this scores 0.', 'Only a single source/claim is presented, so direction of effect cannot be cross-compared across independent studies. Per the rule, a single study is scored 1 (not penalized).', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A state-of-the-science review reports intravaginal TENS as a single therapy has the highest level of evidence for vulvodynia, supported by at least one RCT or comparative effectiveness trial.', NULL, '{c5ce6b09-3a60-4af8-9eb3-a2e9eaa38e8d}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:22.181447+00:00', '2026-06-16T18:10:22.181472+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('ebbf5e3d-f86a-4b34-9e94-9c04cfc84c23', '94c0e763-3091-4e97-b206-9b83fe0dd49e', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 1, 1, 'Evidence comes from a single review source (''State of the Science'') summarizing the literature, not independent replication. It cites at least one RCT plus non-RCT pre-post studies, but all are reported via one synthesis, capping corroboration at 1.', 'Claim 1 states multimodal physical therapy had the highest level of evidence ''with at least one RCT or comparative effectiveness trial,'' indicating RCT-level design. The supporting source is a state-of-the-science review, both consistent with a rigor score of 2.', 'Both the intervention (multimodal physical therapy) and the condition (vulvodynia) are named directly in the claims and quotes. The source title explicitly concerns vulvodynia.', 'The claims report symptom reduction in vulvar pain and dyspareunia but do not articulate or evidence a specific mechanism for physical therapy. Pelvic physical therapy has a plausible mechanism (addressing pelvic floor dysfunction), but no mechanistic detail is provided here.', 'Both claims point in a favorable direction (highest evidence level plus pre-post pain reduction), but they derive from a single review rather than multiple independent datasets. Direction is consistent but not independently replicated, so a neutral score applies.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A state-of-the-science review reports multimodal physical therapy has among the highest levels of evidence for vulvodynia, supported by at least one RCT and pre-post reductions in vulvar pain and dyspareunia in non-RCT studies.', NULL, '{70b37dca-ae04-4ae5-9b1e-d7f0873932eb,ce937b3f-c19a-472d-8859-924b16dbd270}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:26.895646+00:00', '2026-06-16T18:10:26.895671+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('a124cedd-ffcf-4755-bb6f-73382db19f80', '96027ec1-212d-4827-b22a-a22820c17fe7', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 1, 1, 'The single claim references at least one RCT or comparative effectiveness trial as the basis for lidocaine evidence, but cites only one review source describing this. There is no indication of multiple independent corroborating studies, so this remains at the level of a single synthesis/source.', 'The claim explicitly states overnight 5% lidocaine ointment had ''at least one RCT or comparative effectiveness trial'' for vulvodynia, indicating RCT-level evidence. This supports a high rigor score.', 'Both the intervention (overnight 5% lidocaine ointment) and condition (vulvodynia) are named directly in the claim and quote. The match is exact.', 'Lidocaine is a topical anesthetic with a plausible mechanism for reducing vulvar pain, though no explicit mechanism is described in the claim. The mechanism is plausible but not evidenced in the text shown.', 'Only a single source/claim is provided describing the evidence level, so directional agreement across studies cannot be assessed. Per convention, a single source is scored 1 (not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A state-of-the-science review reports that overnight 5% lidocaine ointment has the highest level of evidence for vulvodynia, supported by at least one RCT or comparative effectiveness trial.', 'Topical lidocaine acts as a local anesthetic, blocking sodium channels to reduce vulvar nociceptive pain.', '{86d8761d-6e07-45a9-8cf5-15a9a7ea8047}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:27.469666+00:00', '2026-06-16T18:10:27.469697+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('4a57ea54-3df7-4764-b993-0b59bb59a1c6', '096931a8-b258-4d9c-94cd-243ff75993ad', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 1, 2, 0, 1, 'The single claim references ''at least one RCT or comparative effectiveness trial'' from a single review article (''State of the Science''), which provides no independent replication. This is a lone synthesis statement, not multiple genuinely independent consistent studies.', 'The claim mentions at least one RCT, but the verified evidence is a narrative review statement rather than the RCT itself, and no design details, effect sizes, or outcomes are provided. Without the actual trial data shown, only modest rigor can be credited.', 'Both the intervention (acupuncture) and the condition (vulvodynia) are explicitly named in the claim and quote. The statement directly concerns acupuncture for vulvodynia.', 'No mechanism for how acupuncture would treat vulvodynia is asserted or evidenced in the claim. The quote only states a level of evidence, providing no mechanistic basis.', 'Only a single review-derived claim is available, so directional agreement across multiple studies cannot be assessed. Per rules, a single source is scored 1 rather than penalized.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A review of vulvodynia treatments states that acupuncture had the highest level of evidence, supported by at least one RCT or comparative effectiveness trial.', NULL, '{7bbb1d35-5c71-41ed-aa87-624df74e63c3}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:28.223340+00:00', '2026-06-16T18:10:28.223363+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('94f69f26-6b96-4ad2-9b6e-f0f9949487bb', '0048d3c7-d10d-463c-a861-6434c84b2868', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 1, 2, 2, 1, 1, 'The single source is an umbrella review (''Menopausal hormone therapy and women''s health: An umbrella review''), which is one synthesis rather than multiple independent studies. Per scoring rules, a single systematic review/meta-analysis scores 1, not 2.', 'An umbrella review aggregates systematic reviews and meta-analyses, placing it at the top of the evidence hierarchy, scoring 2. The claim derives from a high-level synthesis rather than a single primary observational study.', 'The claim names both the intervention (intravaginal ET) and the condition outcome (vaginal atrophy, a menopausal symptom) directly. Both drug and indication are explicitly identified in the quote.', 'Intravaginal estrogen acting on vaginal atrophy is mechanistically plausible given estrogen''s trophic effects on vaginal tissue, but no explicit mechanism is described in the claim. The benefit is asserted/observed rather than mechanistically evidenced here.', 'Only a single source/claim is provided, so directional agreement across studies cannot be assessed. Per rules, a single source is scored 1 (n/a, not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'An umbrella review found intravaginal estrogen therapy beneficial for vaginal atrophy, a menopausal condition.', 'Local intravaginal estrogen restores trophic effects on vaginal epithelium, reversing atrophic changes associated with menopausal estrogen decline.', '{3f6ba9d9-621b-4cec-8b35-1cda5eb97214}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:30.375886+00:00', '2026-06-16T18:10:30.375916+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('8b402595-1f02-4292-978c-956446997369', 'a6a456c2-0a7c-49d0-9f32-92d18683ba19', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 1, 2, 1, 0, 1, 'The single source is an umbrella review (''Menopausal hormone therapy and women''s health: An umbrella review''), which is one synthesis rather than multiple independent studies. A single review scores 1 and does not constitute independent replication.', 'The source is an umbrella review of systematic reviews/meta-analyses, which falls in the highest design tier. However, the verified claim provides only a terse fragment without effect sizes or confidence intervals.', 'Estrogen therapy (ET) is named directly, but the claim quote references only ''cardiovascular mortality (ET)'' and does not explicitly tie the benefit to menopause as the condition. The link to menopause is only implied by the source title (menopausal hormone therapy).', 'The claim merely asserts that ET was ''beneficial for cardiovascular mortality'' without describing any biological mechanism. No mechanistic pathway is provided in the verified claim.', 'Only a single source and a single direction of effect are reported, so cross-study consistency cannot be evaluated. Per the rule, a single source is scored 1 and not penalized.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'An umbrella review reports that estrogen therapy was beneficial for cardiovascular mortality in menopausal women.', NULL, '{b2c4fadd-2b7e-408e-96a2-3e38b941e1d5}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:34.827063+00:00', '2026-06-16T18:10:34.827089+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('fca6d7f6-3159-43fd-92b0-a8e165ec915a', '5c8abcf1-4652-4321-8825-7badc300906f', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'direct', 1, 2, 2, 0, 1, 'The single source is an umbrella review (a synthesis of reviews), which counts as one source and is not independent replication. A single review scores at most 1, and the verified claim provides only a fragmentary quote without effect size or multiple consistent studies.', 'The source is an umbrella review (''Menopausal hormone therapy and women''s health: An umbrella review''), which sits at the top of the evidence hierarchy alongside meta-analyses, warranting a rigor score of 2 by design type.', 'The claim explicitly names EPT (estrogen-progestogen therapy) and concerns menopausal hormone therapy outcomes, directly linking this intervention to a menopausal-population safety outcome (lung cancer mortality).', 'The verified quote (''lung cancer mortality (EPT)'') is a bare label with no mechanistic explanation for how EPT would increase lung cancer mortality. No mechanism is asserted or evidenced.', 'Only a single fragmentary claim from one source is available, so directional agreement across studies cannot be assessed; per the n/a rule this defaults to 1 without penalty.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'An umbrella review reported EPT to be associated with harm for lung cancer mortality in menopausal women.', NULL, '{096ac767-3c3a-40c5-9379-4b2a3d83a64b}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:36.214991+00:00', '2026-06-16T18:10:36.215021+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('141f7506-0b37-49c6-b731-91ff06bbd09f', '27be2483-5066-48e8-aa58-2e3bb9f188b5', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 0, 2, 1, 1, 'The evidence rests on a single statement summarizing non-RCT studies of gabapentin cream. No independent replication or large low-bias RCT is presented; the claim references uncontrolled pre-post observations within one review narrative.', 'The claim explicitly describes ''non-RCT studies'' with pre-to-posttest comparisons, i.e., uncontrolled observational designs. There is no RCT, meta-analysis, or active guideline evidence cited.', 'Both the intervention (gabapentin cream) and the condition (vulvodynia, vulvar pain/dyspareunia) are named directly in the claim and source title ''Evaluation and Treatment of Vulvodynia''.', 'Topical gabapentin acting locally to reduce neuropathic vulvar pain is mechanistically plausible, but the claim provides no explicit evidenced mechanism, only observed symptom reduction.', 'Only a single summary source is available, so directional consistency across independent studies cannot be assessed and is scored neutrally. The observed direction (pain reduction) is positive but uncorroborated.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Non-RCT studies summarized in a vulvodynia review reported pre-to-posttest reductions in vulvar pain and/or dyspareunia with gabapentin cream.', 'Topically applied gabapentin may reduce local neuropathic vulvar pain by modulating peripheral nociceptive signaling.', '{06f26f41-e685-47e8-8aa1-6164161b1e20}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:38.567301+00:00', '2026-06-16T18:10:38.567332+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('14c7245e-e873-4e43-9736-e090e4eaab9a', '5b856ad5-0fd4-4b84-9b44-ade55ef65495', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 0, 2, 0, 1, 'Evidence rests on a single review citation describing ''non-RCT studies'' of amitriptyline cream with pre-to-posttest reductions. No independent replication is demonstrated and the underlying data are uncontrolled, so this is a single low-quality source.', 'The claim explicitly references ''non-RCT studies'' with only pre-to-posttest comparisons, i.e., uncontrolled observational designs. This is the weakest design tier with no control arm.', 'The claim names amitriptyline cream directly and addresses vulvar pain/dyspareunia in the context of vulvodynia, matching both intervention and condition.', 'No mechanism for amitriptyline cream''s effect on vulvar pain is asserted or evidenced in the provided claim; only an outcome observation is reported.', 'Only a single source/claim is available, so directional agreement across independent studies cannot be assessed; not penalized per single-study rule.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Uncontrolled non-RCT studies reported pre-to-posttest reductions in vulvar pain and/or dyspareunia with amitriptyline cream.', NULL, '{23e184ea-8a2e-430c-9fb3-dc534fe72398}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:42.853606+00:00', '2026-06-16T18:10:42.853636+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('ca925bf1-716d-4a06-be18-ec88cf4c03ae', 'bcfb7a1e-91c8-49ba-8065-1a54a01a783d', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 0, 2, 0, 1, 'Evidence comes from a single source describing non-RCT (pre-posttest) studies, with no independent replication demonstrated for this specific combination. The claim aggregates uncontrolled studies, which does not meet the bar for independent corroboration.', 'The only claim explicitly references ''non-RCT studies'' with pre-to-posttest designs, which are uncontrolled observational designs at the low end of the rigor scale. No RCT or controlled comparison is reported.', 'Both the intervention (''amitriptyline with baclofen cream'') and the condition (vulvodynia, vulvar pain/dyspareunia) are named directly in the claim and source title.', 'The claim only reports a clinical reduction in pain; no mechanism of action for the amitriptyline/baclofen cream is asserted or evidenced in the provided text.', 'Only a single source/claim is provided, so direction-of-effect agreement across independent studies cannot be assessed and is scored as n/a (1).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Uncontrolled non-RCT studies reported pre-to-posttest reductions in vulvar pain and/or dyspareunia with amitriptyline plus baclofen cream.', NULL, '{ca1d8b46-c5ea-40a9-8193-643266075c4d}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:43.687548+00:00', '2026-06-16T18:10:43.687574+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('949307d1-4c26-4921-b8b3-f1891be42194', 'fef84e81-3835-4be4-9d45-da325e8a2f95', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 1, 2, 0, 1, 'Evidence rests on a single source describing non-RCT studies with only pre-to-posttest comparisons, lacking independent replication or controlled design. A single primary/observational synthesis without independent corroboration scores 0.', 'The claim explicitly references ''non-RCT studies'' showing pre-to-posttest reduction, which constitutes uncontrolled observational evidence. This design level merits a score of 1, not 2.', 'Both itraconazole (''oral itraconazole therapy'') and vulvodynia (vulvar pain/dyspareunia) are named directly. The intervention and condition are clearly identified.', 'No mechanism is asserted or evidenced in the claim; it merely reports symptom reduction without explaining how itraconazole would relieve vulvar pain. Mechanism is absent, scoring 0.', 'Only a single line of non-RCT evidence is presented for itraconazole, so directional agreement across studies cannot be assessed. Per rule, a single study/source is scored 1 (not penalized).', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Non-RCT studies reported pre-to-posttest reduction in vulvar pain and/or dyspareunia with up to 6 weeks of oral itraconazole therapy.', NULL, '{62b29a53-0ea3-450c-bedb-3c91e7d0a71d}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:47.036054+00:00', '2026-06-16T18:10:47.036081+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('b285e650-b218-48e1-9c8b-a24398d60e01', '62c8f83d-7f99-4710-a529-e281876e08f0', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 0, 2, 0, 1, 'The single source describes non-RCT (pre-posttest) studies of vaginal dilators, representing low-grade single-source evidence. No independent replication or pooled synthesis specifically supports dilators for vulvodynia, so this scores at the bottom.', 'The claim explicitly states these were ''non-RCT studies'' with only pre to posttest comparisons, which is uncontrolled observational/case-series level evidence. This is the weakest design tier.', 'Both the intervention (vaginal dilators) and the condition (vulvodynia, with outcomes of vulvar pain and dyspareunia) are named directly in the source titled ''Evaluation and Treatment of Vulvodynia.''', 'No mechanism is described in the claim for how vaginal dilators reduce vulvar pain or dyspareunia; only an outcome reduction is asserted without mechanistic explanation.', 'Only a single source/arm is provided reporting a pre-post reduction, so directional agreement across independent studies cannot be assessed and is scored as not-penalized.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Non-RCT pre-posttest studies reported a reduction in vulvar pain and/or dyspareunia with vaginal dilators in vulvodynia.', NULL, '{63a6f0c9-a8e5-4a50-8e60-8d0d09c00cda}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:50.856555+00:00', '2026-06-16T18:10:50.856600+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('abfb06dc-f981-4cde-bd76-59e8ea809899', '7b7197d4-154c-469b-9fbf-1b98878517f0', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 1, 2, 0, 1, 'The single claim references non-RCT studies of EMG biofeedback within one review article. This is a single source describing pre-post observational data, not independent replication or a well-powered RCT, warranting the lowest score.', 'The evidence is explicitly from ''non-RCT studies'' showing pre-to-posttest reductions, which constitutes uncontrolled observational/small trial data. This corresponds to a rigor score of 1, not the RCT/meta-analysis tier.', 'Both the intervention (electromyography biofeedback) and the condition (vulvar pain/dyspareunia in vulvodynia) are named directly in the claim and source title ''Evaluation and Treatment of Vulvodynia.''', 'The claim only reports an outcome (reduction in pain/dyspareunia) without describing any mechanism by which EMG biofeedback achieves this effect. No mechanistic basis is asserted or evidenced.', 'Only a single source with grouped non-RCT data is provided, so directional agreement across independent studies cannot be assessed. Per the rule, a single study/source is scored 1 rather than penalized.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Non-RCT studies summarized in one review reported pre- to post-treatment reductions in vulvar pain and/or dyspareunia with electromyography biofeedback.', NULL, '{c6ee56ad-d1ae-4c99-ae86-fa7dca6ba81d}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:51.912564+00:00', '2026-06-16T18:10:51.912593+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('1edd68df-b82e-4a12-8ecd-3f7e739a09f0', 'fb15aea5-2e62-4eb4-89ce-8b4dce86cd03', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 1, 2, 0, 1, 'The single claim derives from one review listing hypnotherapy among interventions showing pre-to-posttest reductions in non-RCT studies. This is a single source describing uncontrolled data, not independent replication of hypnotherapy specifically.', 'The claim explicitly references ''non-RCT studies'' (uncontrolled pre-post designs), which constitutes low-quality observational evidence. Although the source is a review, the underlying hypnotherapy data are pre-post non-randomized.', 'Both the intervention (hypnotherapy) and the condition (vulvodynia, with vulvar pain and dyspareunia) are named directly in the claim and source title.', 'No mechanism for how hypnotherapy reduces vulvar pain or dyspareunia is asserted or explained in the claim. The evidence is purely outcome-based.', 'Only a single source with non-RCT data is provided for hypnotherapy; there is no second study to assess directional agreement, so this is scored as not applicable.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Uncontrolled non-RCT studies reported pre-to-posttest reductions in vulvar pain and/or dyspareunia with hypnotherapy.', NULL, '{fd50df3f-a966-43c6-a7aa-34d04418ca7d}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:10:54.437804+00:00', '2026-06-16T18:10:54.437827+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('f285c234-6bd4-4b6c-a5bb-2432da8d6f68', '8671204c-055a-4baa-9e28-e121e72d3d8b', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 1, 2, 0, 1, 'Only a single source is cited, and it describes non-RCT pre-to-posttest observational findings for CBT among many interventions. A single primary/non-RCT source scores 0; there is no independent replication.', 'The claim explicitly references ''non-RCT studies'' showing pre-to-posttest reduction, which is uncontrolled observational evidence. This corresponds to small/observational design, not an RCT or meta-analysis.', 'Both the intervention (cognitive behavioral therapy) and the condition (vulvodynia, with vulvar pain/dyspareunia outcomes) are named directly in the source from a vulvodynia state-of-the-science review.', 'The claim only reports an observed pre-to-posttest reduction without articulating any mechanism by which CBT reduces vulvar pain. No mechanistic basis is asserted or evidenced in the quote.', 'Only a single source/finding is provided, so directional agreement across studies cannot be assessed. Per the n/a rule, this defaults to 1.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Non-RCT studies reported a pre- to post-treatment reduction in vulvar pain and/or dyspareunia with cognitive behavioral therapy for vulvodynia.', NULL, '{60371b73-aad9-437a-abc8-7ced2c21aae3}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:00.588653+00:00', '2026-06-16T18:11:00.588682+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('e0f3cb6e-80b6-4bd7-be26-9705693c808a', 'fc4a10f2-2529-463c-beb8-ccd4e6f50aef', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 1, 2, 1, 1, 'The single source cites only non-RCT studies showing pre-to-posttest reduction, and cold knife vestibulectomy is listed among many interventions without detailed independent replication. This represents a single review reference to uncontrolled studies, not multiple independent or low-bias studies.', 'The claim explicitly describes ''non-RCT studies'' with pre-to-posttest designs, which are observational/uncontrolled in nature. This warrants a rigor score of 1 rather than 2 since no RCT or controlled comparison is reported.', 'Both the intervention (cold knife vestibulectomy) and the condition (vulvodynia, manifesting as vulvar pain/dyspareunia) are named directly. The source title ''Evaluation and Treatment of Vulvodynia'' confirms the condition match.', 'Surgical removal of vestibular tissue plausibly reduces localized vulvar pain and dyspareunia, but the claim only asserts an observed outcome without describing a mechanism. Mechanism is plausible but not explicitly evidenced in the quote.', 'Only a single grouped reference to non-RCT studies is provided without multiple separately reported results to compare. With effectively one synthesized observation, consistency cannot be assessed and defaults to 1.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Non-RCT studies report a pre-to-posttest reduction in vulvar pain and/or dyspareunia following cold knife vestibulectomy for vulvodynia.', 'Surgical excision of the painful vulvar vestibular tissue may reduce localized nociceptive input and thereby decrease pain and dyspareunia.', '{485a1113-24ae-4184-9470-aafe55790346}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:01.198830+00:00', '2026-06-16T18:11:01.198857+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('8742cb54-a0ca-499f-9e2c-0d4b9a0a5147', 'c8b4887c-e5a6-45c5-a254-16c4398933d9', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 0, 2, 0, 1, 'Evidence comes from a single review describing non-RCT (pre-post) studies of laser therapy; only one source is cited and the underlying studies are uncontrolled. This does not meet the bar for independent replication.', 'The claim explicitly notes the laser therapy data come from ''non-RCT studies'' showing only pre-to-posttest reductions, which are uncontrolled observational designs and the lowest tier of rigor.', 'The source directly names both ''laser therapy'' and ''vulvodynia'' (Evaluation and Treatment of Vulvodynia), satisfying both intervention and condition specificity.', 'No mechanism for how laser therapy reduces vulvar pain is asserted or evidenced in the claim; only an outcome observation is reported.', 'Only a single source/arm with non-RCT data is presented, so directional consistency across independent studies cannot be assessed and defaults to neutral.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Uncontrolled non-RCT studies report pre-to-posttest reductions in vulvar pain and/or dyspareunia with laser therapy for vulvodynia.', NULL, '{7e731777-8419-45d4-8efd-3a276e5f5ab4}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:04.244694+00:00', '2026-06-16T18:11:04.244716+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('d0ec5342-90c3-4302-97a0-f73a178e8f91', '6c6485c3-ab87-4814-a0e4-d20ffe1f97ae', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'Evidence comes from a single network meta-analysis (NMA), which counts as one synthesis rather than independent replication. A single systematic review/meta-analysis scores 1; the pooled trials inside do not count as independent sources.', 'The source is a systematic review and meta-analysis with a network meta-analysis, which qualifies as the highest design tier. The claim derives from an NMA comparing treatment modalities.', 'The claim names oral desipramine (with or without lidocaine) directly and the condition is vestibulodynia (a vulvodynia subtype). Both the intervention and condition are explicitly identified.', 'The claim only reports an efficacy outcome (improved ISS vs. other treatments) without describing or evidencing any mechanism of action for desipramine in vulvodynia. No mechanistic hypothesis is asserted.', 'Only a single NMA result is presented, so directional agreement across multiple independent studies cannot be assessed. Per the n/a rule, a single source is scored 1 without penalty.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A network meta-analysis found oral desipramine with or without lidocaine significantly improved an intercourse symptom score versus other treatments for vestibulodynia in women.', NULL, '{1852f043-29bd-4b66-ad48-60891aad3597}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:09.085105+00:00', '2026-06-16T18:11:09.085130+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('4c897497-8eb7-4c3c-8d57-c46af6478e36', '2354bf61-b3f4-4aca-8cdf-09b1552e7918', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'All claims derive from a single source, an RCT (''Gabapentin for the Treatment of Vulvodynia: A Randomized Controlled Trial''). A single primary study normally scores 0, but this appears to be a well-designed RCT with adjusted analyses and confidence intervals; however, with no independent replication and no stated large sample, it warrants only a 1 at most—given it is a single primary trial, scoring 1 reflects a credible RCT.', 'The source is explicitly a randomized controlled trial with placebo comparison and adjusted means with confidence intervals (claims 3-4). RCT design merits the highest rigor score.', 'Both the drug (gabapentin) and condition (vulvodynia) are named directly throughout, including in the title and claim 7 (''do not support the recommendation of gabapentin alone as treatment for vulvodynia'').', 'No mechanism is described in the claims; the trial reports null efficacy outcomes without any mechanistic rationale for gabapentin''s action on vulvodynia pain. The findings actually argue against efficacy.', 'Only a single study is presented, so consistency cannot be assessed across independent sources (n/a -> 1). Within the study, all endpoints (tampon test, intercourse pain, daily pain) consistently show no benefit, but this still derives from one trial.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, NULL, false, 'abstract', 'In a randomized controlled trial, gabapentin (including extended-release) did not reduce tampon test, intercourse, or daily pain compared with placebo in women with vulvodynia, and the data do not support gabapentin alone as treatment.', NULL, '{3d50226c-d4a5-4a24-ba21-d21420f125c2,2c27827a-5630-443e-91b8-25e7de00b1e7,2ed4417c-cb54-4356-b1c9-37793d3ec016,18732506-9e99-4f90-88e7-19743b01fad5,758d124e-6c1d-43a9-9e0b-2c4a5c8294c3,42249bc5-c7e8-4b8c-86b0-d902f0ba7229,cfc1d177-2dc4-4a6c-8d85-eb8a8d866d43}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:10.383931+00:00', '2026-06-16T18:11:10.383958+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('16d41b17-2efe-4ead-bdb9-1e2e8085f203', '99f7a146-c741-4c9c-b1a1-f0eef7a1fc23', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 1, 1, 'Evidence comes from a single systematic review and meta-analysis, which counts as one synthesis rather than independent replication. Per the scoring rules, a single review scores 1, not 2.', 'The source is a systematic review and meta-analysis, which qualifies as the highest rigor tier. No single primary RCT details are provided here, but the synthesis design supports a score of 2.', 'The claim explicitly names desipramine and addresses vestibulodynia/sexual function in women, directly linking this drug to this condition. Both intervention and condition are named directly.', 'Desipramine is a tricyclic antidepressant plausibly affecting neuropathic vulvar pain, but the claim only asserts improved sexual function without describing the underlying mechanism. The mechanism is plausible but not evidenced in the quote.', 'Only a single synthesis source is provided, so directional agreement across independent studies cannot be assessed. Per the rules, a single source is scored 1 (n/a, not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis reported improvement in sexual function with oral desipramine, with or without lidocaine, in women with vestibulodynia.', 'As a tricyclic antidepressant, desipramine may modulate neuropathic pain pathways contributing to vulvodynia, thereby improving sexual function.', '{86629708-1fb5-46eb-89de-3db0d53a70f8}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:12.358147+00:00', '2026-06-16T18:11:12.358177+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('409ac67a-16b7-40e9-b5cc-f9a1b6e51efa', 'f624a6f2-f6b5-4143-9bc8-9a684cc0a2fd', 'a035d965-d5fa-47a6-a504-7941ffc64fc5', 'efficacy', 'direct', 1, 2, 1, 0, 1, 'The single source is a systematic review and meta-analysis, which counts as one synthesis (score 1), not independent replication. The pooled trials inside are not counted as independent sources.', 'The source is explicitly a ''Systematic review and meta-analysis'', which qualifies for the highest rigor tier. Study design strength is therefore 2.', 'The condition (vestibulodynia) is named directly, but the intervention is only ''several existing interventions''/''multiple interventions'' with no specific drug or modality identified. This vagueness prevents a full specificity score.', 'No mechanism is asserted or evidenced; the claim only states a lack of association with improvement. Without any named intervention or proposed mechanism, plausibility cannot be supported.', 'Only a single source/claim is provided, so directional agreement across studies cannot be assessed and is scored as n/a (1). The claim itself is uniformly negative but there is nothing to compare.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis found that several existing interventions were not associated with improvements in vestibulodynia in women.', NULL, '{cbb785a9-e37c-4f96-a299-17da3cf55603}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:13.795126+00:00', '2026-06-16T18:11:13.795152+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('72454386-f7e4-4645-abdb-cb5c080df51e', 'd6e0d47f-261a-490d-b935-ca89fedf0f76', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'The evidence comes from a single systematic review (''Treatment of Provoked Vulvodynia: A Systematic Review''). A single synthesis scores 1 and does not constitute independent replication of trials pooled within it.', 'The source is a systematic review, which qualifies as high-rigor design (score 2). However, the review itself notes ''low certainty of evidence'' for the underlying effects.', 'Both the intervention (multimodal physiotherapy) and the condition (provoked vulvodynia) are named directly in the claim and quote.', 'No mechanism is described in the claim; it only reports a comparative treatment effect favoring physiotherapy over lidocaine without explaining how physiotherapy acts on vulvodynia.', 'Only a single source is provided, so directional consistency across studies cannot be assessed; per rules this is scored 1 and not penalized.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review found low-certainty evidence that multimodal physiotherapy significantly outperforms lidocaine for provoked vulvodynia.', NULL, '{e4745c70-4175-4a43-9c24-9dd7c116111e}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:17.620272+00:00', '2026-06-16T18:11:17.620312+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('3dbd624e-eb6c-479c-a2cd-3570bb402dc2', 'd03a5cc9-1542-4477-8dd2-b8bbae524b52', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 1, 2, 1, 0, 2, 'All three claims derive from a single systematic review and meta-analysis of treatment modalities for vestibulodynia. A single synthesis is not independent replication, so this caps at 1 rather than 2.', 'The evidence is a systematic review and meta-analysis pooling multiple interventions with pooled effect estimates and confidence intervals (e.g., MD = 0.08; 95%CI = -0.49 to 0.64). Meta-analysis qualifies for the top rigor tier.', 'The condition (vestibulodynia/dyspareunia in women) is named directly, but the ''interventions'' are not specified as any single named drug or treatment; the arm is a generic basket of interventions. Drug/intervention specificity is therefore absent.', 'The claims report null effects on dyspareunia, DVS, and MPQ with no mechanism described. No biological mechanism is asserted or evidenced for any specific intervention.', 'Across three distinct outcomes (dyspareunia, DVS, MPQ) the findings consistently point to no reduction, all with confidence intervals crossing the null. The direction agrees across all reported outcomes within this synthesis.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, NULL, false, 'abstract', 'A systematic review and meta-analysis found that interventions for vestibulodynia did not significantly reduce dyspareunia, DVS, or MPQ pain measures (all CIs crossing null).', NULL, '{f813294a-f8be-4df9-9640-575be0e6a892,6936b856-977a-4f36-ac28-2a6692c11cfb,b1e94758-abbb-4e06-9703-484aab9fe47f}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:18.504554+00:00', '2026-06-16T18:11:18.504580+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('a667556f-c7dc-4e79-ab8c-3599b642c856', 'dcd5ca46-ee57-4d35-b7e1-07b887d30b22', '1262bc49-cef8-4cf4-bc1c-546db828451b', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'Evidence comes from a single meta-analysis ("An in-depth meta-analysis"). A single synthesis scores 1 per the rubric since it does not constitute independent replication and the pooled trials inside are not counted as separate sources.', 'The source is a meta-analysis, which qualifies for the highest rigor score of 2. The single verified claim reports a quantitative VAS reduction pooled across studies.', 'The claim names dienogest directly and explicitly addresses dysmenorrhea ("Dienogest significantly improved dysmenorrhea"). Both the intervention and condition are named.', 'No mechanism is asserted or evidenced in the verified claim; only an efficacy outcome (VAS reduction) is reported. With no mechanistic statement, plausibility scores 0.', 'Only a single source/claim is provided, so directional agreement across studies cannot be assessed. Per the rubric, a single study is scored 1 (n/a, not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A meta-analysis found dienogest significantly improved dysmenorrhea, with a mean VAS reduction of 6 on a 10-point scale.', NULL, '{72b7a5b3-c3b0-4f50-8626-361e46c9c641}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:20.776174+00:00', '2026-06-16T18:11:20.776201+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('f5c59e67-c75d-4366-a480-0cfe836ed284', 'dcd5ca46-ee57-4d35-b7e1-07b887d30b22', '61143789-de48-488b-968b-f3f71189f1bc', 'efficacy', 'direct', 2, 2, 2, 1, 2, 'Evidence comes from two independent systematic reviews/meta-analyses (Dienogest in-depth meta-analysis and the LNG-IUS comparison meta-analysis), both consistently finding dienogest effective for adenomyosis. Two distinct syntheses agreeing in direction supports a high score, though neither is a single large RCT.', 'Both sources are explicitly meta-analyses (claims 1-12 cite ''meta-analysis'' and ''systematic review and meta-analysis''), the highest study-design tier.', 'Claims name both dienogest and adenomyosis directly (e.g., ''Dienogest substantially alleviates dysmenorrhea in women with adenomyosis'' and ''more effective than LNG-IUS for the management of adenomyosis'').', 'The claims describe outcomes (reduced pelvic pain, reduced uterine volume) consistent with a progestin acting on adenomyotic tissue, but no explicit mechanism is stated in the quotes. Mechanistic plausibility is implied rather than evidenced.', 'Both independent meta-analyses agree dienogest is effective and reduces dysmenorrhea/pelvic pain; the comparison review further shows superiority over LNG-IUS for pain and uterine volume. The only negative (lower haemoglobin) is a safety signal, not a contradiction of efficacy.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Strong', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Two meta-analyses indicate dienogest substantially alleviates dysmenorrhea and pelvic pain and reduces uterine volume in women with adenomyosis, with superiority over LNG-IUS for pain and uterine volume.', 'As a progestin, dienogest may suppress adenomyotic tissue activity, reducing pelvic pain and uterine volume.', '{04bced38-338e-4079-9d06-8933782ca0e1,bd0bb58b-e333-4fcf-9a25-1a23abc6a348,61cfa204-5936-4a2e-90f8-26f5c9c76095,474683c7-87f6-49ee-92d5-148675102353,a397f4d8-2307-4ff9-8a3a-3d276c9fa370,cad9880e-7c5f-4b7a-85d5-afbfbc175e5e,3a1b366e-788c-4ed7-9a34-0ff46120bdbd,649a9e0f-ab77-4a4e-970c-5c21e19f99fe,7a33008f-c1b6-4b84-be6e-f1c3507bc522,ceda142b-8deb-4aaa-b2d0-ea5e510fbf56,fc857b4d-4f21-49d2-b36a-cf3d2a36d5de,55f6e0c0-2f4a-4a83-956d-d5c7b612726b}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:21.780437+00:00', '2026-06-16T18:11:21.780465+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('6a25a159-c42c-4706-b12c-f373beb6b3d8', '207bc176-7427-4edd-8f0d-4e9f0efbf43e', '61143789-de48-488b-968b-f3f71189f1bc', 'efficacy', 'direct', 1, 2, 2, 1, 1, 'Evidence comes from a single systematic review and meta-analysis comparing LNG-IUS and dienogest. Per scoring rules, a single synthesis scores 1 and does not count the pooled trials as independent sources.', 'The source is a systematic review and meta-analysis, which qualifies as the highest design tier (score 2).', 'Both the intervention (LNG-IUS) and the condition (adenomyosis) are named directly in the source title and claim.', 'Higher haemoglobin plausibly reflects reduced menstrual blood loss from progestin-induced endometrial suppression, but no explicit mechanism is described in the claim. This is a plausible, not evidenced, mechanism.', 'Only a single comparative outcome (haemoglobin) is reported, so directional consistency across multiple findings cannot be assessed; per rules a single result scores 1.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis found that LNG-IUS was associated with significantly higher haemoglobin levels than dienogest in women with adenomyosis.', 'LNG-IUS may reduce menstrual blood loss via local progestin-induced endometrial suppression, improving haemoglobin levels.', '{42dc0769-9b92-402c-a5a2-1b0363da552e}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:25.059635+00:00', '2026-06-16T18:11:25.059660+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('5376cf93-8f42-4dc3-8cce-48e2fd05707f', '56c09d87-ef14-4c95-8c3f-05e69349c924', '61143789-de48-488b-968b-f3f71189f1bc', 'safety', 'direct', 1, 2, 1, 0, 1, 'Evidence comes from a single systematic review and meta-analysis comparing LNG-IUS and dienogest. A single synthesis counts as 1, not independent replication, since the pooled trials are not separate verified sources here.', 'The source is a systematic review and meta-analysis, which scores 2 on study design. The claim reports comparative side-effect data across treatment groups.', 'The condition adenomyosis is named directly in the source title, but the intervention is only described as ''unspecified treatment groups'' in the claim; the underlying drugs (LNG-IUS, dienogest) appear in the title but the verified claim itself does not name a specific intervention.', 'The claim is purely a tabulation of side-effect occurrence being comparable between groups, with no mechanism asserted or evidenced for why these adverse effects arise.', 'Only one synthesis with a single comparative statement is provided, so directional agreement across independent sources cannot be assessed; scored as n/a (1).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis of treatments for adenomyosis found that side effects such as weight gain, breast tenderness, headache, mood disturbance, and reduced libido were comparable between the two treatment groups.', NULL, '{762b2fd4-5809-4091-9375-329b336df4fa}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:26.071934+00:00', '2026-06-16T18:11:26.071964+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('0bd24db6-066e-406f-b00e-03ef05f4b23a', '784fd705-d794-4b1b-8ce1-8f91de6503f6', '61143789-de48-488b-968b-f3f71189f1bc', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'The single source is a systematic review and meta-analysis, which scores 1 per the rubric (one synthesis is not independent replication). Only one source is presented, supporting claim 1 about increased natural conception.', 'The evidence is from a systematic review and meta-analysis, which qualifies as rigor level 2. The source title explicitly identifies it as a ''Systematic Review and Meta-analysis.''', 'Both the intervention (surgical treatment) and condition (adenomyosis) are named directly in the claim: ''Surgical treatment increases natural conception in women with adenomyosis.'' The drug/intervention and condition are explicit.', 'The claim asserts an effect on conception but no mechanism is provided in the verified claims. No physiological pathway is described or evidenced linking surgical treatment to improved conception.', 'Only a single source/claim is provided, so directional agreement across studies cannot be assessed. Per the rubric, a single study is scored 1 (n/a, not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis reports that surgical treatment increases natural conception in women with adenomyosis.', NULL, '{2511ff1a-088d-4f1c-a928-2171a5f54494}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:29.015587+00:00', '2026-06-16T18:11:29.015612+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('6fffa916-45f2-48bc-be7a-2917c3f12313', 'f88b2f32-3a98-4648-bd1a-7935f304e65d', '61143789-de48-488b-968b-f3f71189f1bc', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'Evidence comes from a single systematic review and meta-analysis, which counts as one synthesis rather than independent replication. Per the rubric a single systematic review scores 1.', 'The source is a systematic review and meta-analysis, which qualifies for the top rigor tier. The single claim is drawn from this synthesis.', 'Both the intervention (GnRHa) and condition (adenomyosis) are explicitly named in the claim and the study title. The claim directly addresses GnRHa''s effect on IVF outcomes in adenomyosis.', 'No mechanism is described in the claim; it simply states GnRHa does not improve IVF outcomes. No mechanistic rationale is asserted or evidenced.', 'Only a single source/claim is provided, so directional consistency across studies cannot be assessed. Per the rubric a single study defaults to 1.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis found that GnRHa treatment does not improve IVF outcomes in women with adenomyosis.', NULL, '{e49f7fe4-54e2-498c-a712-3e6ab5896ec8}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:31.397845+00:00', '2026-06-16T18:11:31.397869+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('1427a47f-026c-4557-8847-6da08e19ce12', '78d6e883-9c70-4950-9259-f01f1c475997', '61143789-de48-488b-968b-f3f71189f1bc', 'efficacy', 'direct', 1, 2, 2, 0, 1, 'The single source is a systematic review and meta-analysis, which counts as one synthesis (score 1, not independent replication). Only one source is provided and it reports a single conclusion about GnRHa pretreatment.', 'The source is explicitly a ''Systematic Review and Meta-analysis,'' which qualifies for the highest rigor tier under the design rubric.', 'Both the intervention (GnRHa/GnRH agonist) and the condition (adenomyosis) are named directly in the claim and the source title concerns uterine adenomyosis and GnRHa pretreatment.', 'No mechanism is described in the verified claim; it states only a clinical conclusion that long-term GnRHa pretreatment could not be beneficial, with no mechanistic basis asserted or evidenced.', 'Only a single source/conclusion is provided, so directional agreement across studies cannot be assessed; per the rubric this defaults to 1.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A systematic review and meta-analysis concluded that long-term GnRHa pretreatment could not be shown to be beneficial in the context of adenomyosis (IVF outcomes).', NULL, '{9528a085-65d2-4681-b15a-951a0ee3e9e0}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:33.749802+00:00', '2026-06-16T18:11:33.749826+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('d2cfcd5b-ceae-47af-8a89-068189e51dc5', 'e6727c59-a55a-4e1e-ac88-8ea457c7afd8', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'safety', 'direct', 0, 0, 2, 0, 1, 'Only a single source is cited, and it is not even a study evaluating SSRI safety but an article about a different intervention (tryptophan diet and acupuncture). A single mention with no independent replication scores 0.', 'The claim derives from a passing statement in a paper about diet/acupuncture, with no study design, sample, or data supporting the SSRI safety assertion. This is essentially an unsupported assertion, scoring 0.', 'The claim names SSRIs directly and PMDD directly, stating SSRIs ''have several side effects when used to treat PMDD.'' Both intervention and condition are explicitly identified.', 'The claim merely asserts side effects exist without describing any mechanism or pharmacological basis. No mechanistic detail is provided, so this scores 0.', 'Only a single source is provided, so directional consistency cannot be assessed and is scored as n/a (1) per the rubric.', 'F4', 0.75, 'Female representation not stated — applicability to women uncertain (flagged for full text).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single source asserts that SSRIs have several side effects when used to treat PMDD, without specifying which side effects or providing data.', NULL, '{47b372df-5762-4670-a8dd-2175f6d815a7}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:35.643646+00:00', '2026-06-16T18:11:35.643677+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('8a1e736e-33c7-467d-90b8-2958f91e69fe', 'c504c3e4-00a4-451b-936d-8014aac0fa8d', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'efficacy', 'direct', 0, 1, 2, 1, 1, 'Only a single source is presented, and it appears to be a single primary study on a combined intervention rather than an independent body of replicated evidence. A single primary study scores 0.', 'The single claim asserts importance of the intervention but provides no design details; the title suggests an interventional study of modest scope, consistent with a small trial scoring 1. No meta-analysis or large RCT is evidenced.', 'Both the intervention (tryptophan-rich diet) and the condition (PMDD) are named directly in the claim and source title.', 'Tryptophan is a serotonin precursor and serotonergic dysfunction is implicated in PMDD, making the mechanism plausible, but the claim itself asserts importance without presenting mechanistic evidence.', 'Only one source is available, so directional agreement across studies cannot be assessed; per rules a single study is scored 1 (n/a, not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single study recommends tryptophan-rich diet as a complementary treatment for women with PMDD, but it is combined with acupuncture and provides no quantitative efficacy data.', 'Dietary tryptophan is a precursor for serotonin synthesis, which may address the serotonergic dysregulation implicated in PMDD.', '{71c87a41-f02e-4d7e-8018-35e296905740}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:37.141866+00:00', '2026-06-16T18:11:37.141895+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('071bf4af-4a5e-4f09-9125-dcaa7c947ed6', '096931a8-b258-4d9c-94cd-243ff75993ad', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'efficacy', 'direct', 0, 0, 2, 0, 1, 'Only a single source is cited, and the claim is a recommendation statement rather than independent replicated findings. No multiple independent studies or large RCT are presented.', 'The single claim is an assertion about importance of complementary treatment with no described study design, controls, or quantitative outcomes. It reads as an opinion/recommendation, warranting the lowest rigor score.', 'Both the intervention (acupuncture) and condition (PMDD) are explicitly named in the verified claim and source title.', 'No mechanism is described for how acupuncture would alleviate PMDD symptoms. The claim is purely a recommendation with no biological rationale asserted or evidenced.', 'Only a single source is available, so directional agreement across studies cannot be assessed and is not penalized (n/a -> 1).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single source recommends acupuncture as a complementary treatment for women with PMDD, but provides no quantitative efficacy data.', NULL, '{5d60af66-7b2d-4f65-871a-e655f701b38b}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:38.380707+00:00', '2026-06-16T18:11:38.380733+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('63399438-ba83-419e-a623-54c504f6d3d8', '97cc587b-f617-4589-b1df-9139f8a7ca7d', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'efficacy', 'direct', 1, 2, 2, 1, 2, 'All three claims derive from a single source (''Pregnancy in Polycystic Ovary Syndrome II''), which appears to be one RCT (PPCOS II trial). A single primary study provides limited corroboration; no independent replication is shown. The claims are internally consistent but come from one study.', 'The source describes a controlled trial comparing letrozole to clomiphene citrate with hypothesis-driven outcomes (live birth, ovulation, singleton pregnancy), consistent with an RCT design, which scores 2.', 'Both the drug (letrozole) and the condition (PCOS) are explicitly named in all claims, e.g. ''ovulation induction with an aromatase inhibitor (letrozole)... in infertile women with PCOS.''', 'The claims identify letrozole as an aromatase inhibitor used for ovulation induction, contrasting with clomiphene as a SERM, suggesting a plausible mechanism via ovulation. However, the mechanism is only implied, not directly evidenced with data in these claims.', 'Three outcomes (live birth, singleton pregnancy, ovulation rate) all point in the same direction favoring letrozole over clomiphene, showing consistent directionality across endpoints within the source.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Strong', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'In infertile women with PCOS, letrozole was associated with higher ovulation rates and greater likelihood of live birth and singleton pregnancy compared with clomiphene citrate.', 'Letrozole, an aromatase inhibitor, induces ovulation more effectively than the SERM clomiphene citrate in PCOS.', '{0edbc3e8-9d16-4235-b9aa-8f2f9cd259ff,240cd99d-a669-4068-896f-22a7e0cc9d15,17aaaf85-b1e1-4533-950b-6e75001f1632}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:42.655550+00:00', '2026-06-16T18:11:42.655565+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('33041181-18cc-4ba3-953a-eef34f1ee4b1', '97cc587b-f617-4589-b1df-9139f8a7ca7d', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'safety', 'direct', 0, 1, 2, 0, 1, 'Only a single source (Pregnancy in Polycystic Ovary Syndrome II) is cited with one claim. There is no independent replication, so this is a single primary study scoring 0.', 'The source appears to be a single clinical trial (PPCOS II) without further design details such as randomization or sample size in the claims. Without explicit indication of RCT design or meta-analysis in the verified claim, it is scored as a small/observational-level trial.', 'Both letrozole and PCOS are named directly: the source is ''Pregnancy in Polycystic Ovary Syndrome II'' and the claim explicitly concerns letrozole treatment outcomes (first trimester fetal demise).', 'The claim states an outcome (less likely fetal demise vs clomiphene) but provides no mechanism explaining why letrozole would reduce first-trimester loss. No mechanistic rationale is asserted or evidenced.', 'Only a single claim from one source is provided, so directional agreement across studies cannot be assessed; per rules a single study is scored 1 (n/a, not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'In women with PCOS, letrozole treatment was associated with a lower likelihood of first-trimester intrauterine fetal demise than clomiphene citrate, based on a single trial.', NULL, '{d344da20-4ff5-4baa-8644-f6803fa3b164}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:43.548784+00:00', '2026-06-16T18:11:43.548811+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('f406ddd9-5459-4e17-bfdd-6a7618047a39', '3a35025d-5a80-4b01-aede-b7ffd317ed28', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'safety', 'direct', 0, 1, 2, 0, 1, 'Only a single source is cited (Pregnancy in Polycystic Ovary Syndrome II) making one comparative claim about first-trimester fetal demise. There is no independent replication, so this scores at the bottom of the single-source range.', 'The claim derives from a single trial/study (PPCOS II) without a stated design quality, sample size, or effect estimate. Absent evidence of a large, low-bias RCT or meta-analysis, this is scored as observational/small-trial level.', 'The claim explicitly names clomiphene citrate and is in the context of PCOS (Pregnancy in Polycystic Ovary Syndrome), with a direct safety comparison to letrozole. Both the drug and condition are directly identified.', 'The claim states an outcome (higher fetal demise with clomiphene) but provides no mechanistic explanation for why this occurs. No mechanism is asserted or evidenced in the verified quote.', 'Only a single source/claim is available, so directional consistency across studies cannot be assessed. Per scoring rules, a single study is not penalized and defaults to 1.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single PCOS pregnancy trial suggests clomiphene citrate is more likely than letrozole to result in first-trimester intrauterine fetal demise.', NULL, '{7694699c-7914-4bd7-8c6f-3e5fe6c47fe1}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:44.892445+00:00', '2026-06-16T18:11:44.892475+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('1e278b25-e366-4a97-bd72-a2729644b9a1', '97cc587b-f617-4589-b1df-9139f8a7ca7d', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'other', 'direct', 0, 1, 2, 1, 1, 'Only a single source (''Pregnancy in Polycystic Ovary Syndrome II'') supports the cost-effectiveness claim. A single primary study scores 0 with no independent corroboration shown.', 'The claim derives from a single trial-based analysis (PPCOS II); no meta-analysis, guideline, or explicitly described large low-bias RCT design is provided in the claims. The statement is also phrased predictively (''will be''), suggesting a hypothesis/projection rather than firm RCT outcome data.', 'Both the intervention (letrozole) and the condition (Polycystic Ovary Syndrome) are named directly, with a clear comparator (clomiphene). The claim is specific to PCOS and letrozole.', 'A cost-effectiveness advantage is plausible given letrozole''s higher singleton pregnancy rates in PCOS, but no explicit mechanism or economic-model detail is given in the claim. The mechanistic basis is implied rather than evidenced here.', 'Only one source/claim is provided, so directional agreement across studies cannot be assessed. Per rules, a single study defaults to 1 (not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single PCOS trial-based analysis suggests letrozole is more cost effective than clomiphene at achieving singleton pregnancies.', NULL, '{76eb4720-375b-4dd8-9b63-d057d60c5e21}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:46.771199+00:00', '2026-06-16T18:11:46.771224+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('c27ca295-26ba-497f-9aae-07534f51ad4d', '63952f1e-feff-4ffe-b250-3d621d2d84a8', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'efficacy', 'direct', 0, 1, 2, 1, 1, 'Only a single source is cited (a study on Low Dose OC Therapy in Women With PCOS). There is no independent replication, and the single primary study scores 0 for corroboration.', 'The source appears to be a single clinical study examining low-dose OC therapy and BMI impact, with no indication of being an RCT or meta-analysis. This represents observational/small trial level evidence, scoring 1.', 'The claim directly names both the intervention (combined oral contraceptives) and the condition (PCOS), explicitly studying OCs ''in women with PCOS.''', 'The claim asserts that OCs reduce circulating androgens, a mechanistically plausible effect (suppression of ovarian androgen production and increased SHBG), but the quote states the effect without detailing the mechanism, so it is plausible rather than directly evidenced.', 'Only a single claim from a single source is provided, so directional consistency across studies cannot be assessed; per the n/a rule this is scored 1.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single study reports that combined oral contraceptives effectively reduce circulating androgens in women with PCOS.', 'Combined oral contraceptives suppress ovarian androgen production and likely increase SHBG, lowering circulating androgen levels.', '{8fb81677-2ba1-4c02-a16e-b74d085317e5}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:50.667675+00:00', '2026-06-16T18:11:50.667698+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('cd7bbe97-5bee-469e-bba7-24cadf75700c', '0aad9e2a-7e1c-4a4a-bfbf-69a4862a6907', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'other', 'direct', 0, 0, 2, 0, 1, 'Only a single source is cited, and it merely describes a study being conducted (''learn the efficacy'') without reporting any results. This represents at most one primary study with no outcomes, so corroboration is at the lowest level.', 'The claim only states that efficacy is ''being studied'' — no design details, no results, no indication of an RCT or completed trial. With no reported methodology or findings, this scores as preclinical/protocol-level evidence.', 'Both the intervention (Mazdutide) and the condition (polycystic ovary syndrome/PCOS) are named directly in the quote. The population is also specified as obese female adults.', 'No mechanism of action is described or asserted in the claim; it only states an efficacy study is underway. There is no mechanistic link provided between Mazdutide and PCOS.', 'Only a single source with no reported outcomes is available, so directional consistency cannot be assessed. Per the n/a convention, this is scored 1.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'Mazdutide is being studied for efficacy in obese female adults with PCOS, but no results are reported.', NULL, '{ea821a63-f6b1-4a2e-bc00-f845d80c96fc}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:51.067515+00:00', '2026-06-16T18:11:51.067541+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('44adf872-f5d4-40df-a51b-22a146b6ede1', 'db80198e-005a-4723-91a3-3aad5170b2e3', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'direct', 0, 1, 2, 0, 1, 'The single source is a clinical study/trial description (''A Study of the Safety and Effect of Repeated Administration of G-CSF on Hot Flashes in Postmenopausal Women'') with no results reported. A single primary study with no outcome data scores 0; there is no independent corroboration.', 'The claim describes a study assessing efficacy and safety of repeated G-CSF administration, but the design (RCT vs. observational, sample size, controls) is not specified and only the intent to assess is stated. Without confirmed RCT design or results, this is treated as a small/unspecified trial at best.', 'The intervention (G-CSF) and condition (hot flashes/vasomotor symptoms in postmenopausal women, i.e., menopause) are both named directly in the quote. Both drug and condition are explicit.', 'No mechanism is described in the verified claim for how G-CSF would affect hot flashes or vasomotor symptoms. The text only states an intent to assess efficacy, with no asserted or evidenced biological rationale.', 'Only a single source with no reported results is available, so there is nothing to compare for directional agreement. Per scoring rules, a single study is scored 1 (not penalized).', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A study is assessing the efficacy of repeated G-CSF administration for hot flashes and vasomotor symptoms in postmenopausal women, but no efficacy results are reported.', NULL, '{03ead28c-416b-4286-9c30-2a4d48d5d1aa}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:53.632155+00:00', '2026-06-16T18:11:53.632218+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('6af850f7-f840-43f2-92c1-cf832e1c6505', 'db80198e-005a-4723-91a3-3aad5170b2e3', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'direct', 0, 1, 2, 0, 1, 'Only a single source is referenced — a study description/registration for a trial assessing G-CSF safety in postmenopausal women. A single primary study (and one not yet reporting results) scores 0, with no independent corroboration.', 'The single claim describes a study assessing safety of repeated G-CSF administration, but no design details (randomization, control arm, sample size) are provided and no results are reported. Without evidence of an RCT with outcomes, this is treated as a small/unspecified trial at best.', 'Both the intervention (G-CSF) and the condition (menopause, specifically hot flashes/vasomotor symptoms in postmenopausal women) are named directly in the quote.', 'No mechanism is asserted or evidenced in the claim for how G-CSF would affect hot flashes or its safety profile. The quote merely states the study aims to assess efficacy and safety.', 'Only a single source is present and it reports no results, so directional consistency cannot be assessed. Per the n/a rule, this is scored 1 and not penalized.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single study is assessing the safety of repeated G-CSF administration for hot flashes and vasomotor symptoms in postmenopausal women, but no safety results are reported in the verified claim.', NULL, '{8d199f39-b537-4ebc-9342-593ea131d0b0}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:54.884288+00:00', '2026-06-16T18:11:54.884314+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('676f3d75-f043-414b-8edb-127fcc04987a', 'cd4d57c8-1d81-4b7f-ba01-79d966326612', 'ad8df3f9-20b6-47b6-84f9-2097945d5d7b', 'efficacy', 'direct', 0, 0, 2, 0, 1, 'Only a single source is cited, and the quote is a predictive hypothesis (''is predicted to be more efficacious'') rather than a reported result from completed work. There is no independent replication or demonstrated outcome to corroborate efficacy.', 'The claim is a stated prediction/hypothesis (''the localized use of lidocaine will be more efficacious''), not a reported finding from an RCT or meta-analysis. No completed study design or results are presented, so this scores as the lowest rigor tier.', 'Both the intervention (lidocaine) and the condition (vulvodynia) are named directly in the claim. The quote explicitly references localized lidocaine for vulvodynia.', 'No mechanism is described in the claim; it merely asserts an expected superiority over placebo. There is no mechanistic basis provided for how localized lidocaine relieves vulvodynia.', 'Only a single predictive claim is available, so directional agreement across studies cannot be assessed. Per the single-source rule, this is scored neutral rather than penalized.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single source hypothesizes that localized lidocaine will be more efficacious than placebo for vulvodynia, but no completed results are reported.', NULL, '{a1e3b178-4e2d-4770-ab42-c4cddf3cb740}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:59.088660+00:00', '2026-06-16T18:11:59.088689+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('155072e6-482c-4189-b6ac-0419b228d75e', '75c2aadc-cef0-4fd6-ad41-e8b339e019d0', '1a15a12d-0cdb-4c76-9ab9-d544f0e231fe', 'efficacy', 'direct', 0, 1, 2, 1, 1, 'Only a single source is provided, and the verified claim is framed tentatively (''could be'', ''possibly reduce''). No independent replication or pooled synthesis is shown, so this warrants the lowest score.', 'The single study title suggests a treatment study of botulinum toxin A for PVD, but no design details (RCT, sample size, controls) are given in the claims. Absent evidence of a rigorous RCT, this is scored as observational/small-trial level.', 'Both the intervention (Botulinum Toxin A) and the condition (provoked vestibulodynia/PVD) are named directly in the claim and source title.', 'A mechanism is asserted—decreasing high muscle tonus to reduce coital pain—which is biologically plausible for BTA''s known muscle-relaxant action, but the claim is hedged (''possibly'') and not directly evidenced in the provided text.', 'Only a single source/claim is available, so directional agreement across studies cannot be assessed; per convention this is scored as not penalized.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, 'no sample size or CI in source — precision unknown, flagged for full text', true, 'abstract', 'A single study suggests botulinum toxin A may be an option for provoked vestibulodynia by reducing pelvic muscle tone and coital pain, though framed tentatively.', 'Botulinum Toxin A reduces elevated pelvic floor muscle tonus, potentially decreasing coital pain in PVD.', '{a50033f9-20b2-4fd9-9670-1ae549c8d058}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:11:59.145952+00:00', '2026-06-16T18:11:59.145970+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('69e29382-c6b8-43bd-9db9-3d0c39769616', 'a1fd3f26-6434-4c31-a1d3-20b171dd66f4', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'safety', 'pathway', 1, 1, 0, 1, 1, 'Three distinct adverse-event signals (fatigue, depression, insomnia) from FAERS converge on CNS/mood-relevant systems plausibly tied to PMDD symptomatology (claims 1-3). However, all derive from the same single data source (FDA AEMS) and represent raw counts, not independent mechanistic lines.', 'Data come from human female adverse-event reports (claims 1-3), which is human-relevant, but they are raw report counts without disproportionality statistics, explicitly subject to reporting bias and confounding and not evidence of causation. This is weak hypothesis-generating data rather than a rigorous model.', 'The claims provide no information on estrone''s specific molecular target or mechanism; they only tally symptom reports. There is no demonstration of specific action on a defined receptor or pathway relevant to PMDD.', 'Depression, insomnia, and fatigue are symptom domains overlapping with PMDD, suggesting estrone acts on a relevant system (claims 1-3). But the signals are adverse events (potential harm), not therapeutic effect, so the target-phenotype fit is only loosely supported.', 'All three signals point toward CNS/mood-affective effects consistent with one another (claims 1-3). They are directionally coherent as a mechanistic lead, though as adverse events they point toward possible worsening rather than benefit.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'few events (≈21)', false, 'abstract', 'FDA adverse-event reports for estrone in women include fatigue (11), depression (5), and insomnia (5) cases, raw counts that are mechanistic leads but not evidence of causation or benefit for PMDD.', 'Estrone appears to act on CNS/mood-regulating systems (reflected in mood, sleep, and energy adverse-event signals), the same systems implicated in PMDD symptomatology.', '{7390aa7e-2de2-4c89-b75d-3a8909888e68,316a18c2-7ed4-43d1-a6f2-1422ba45331a,c399067e-afb0-4de3-b43b-e3796c03344e}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:09.220046+00:00', '2026-06-16T18:12:09.220072+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('35ffeb42-85e9-420d-8b60-a71206a950dc', 'e9003ea1-ee30-4de7-96ff-158a42eed2ce', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'safety', 'pathway', 1, 1, 0, 1, 2, 'Three claims report co-occurring psychiatric/somatic adverse events (anxiety, depression, fatigue) for ethinyl estradiol in female patients, which converge on a CNS/mood-relevant system. However, all derive from the same single source (FDA AEMS spontaneous reports), so they represent one line of evidence rather than independent mechanistic lines.', 'Data come from a human pharmacovigilance database (real-world, female patients), which is human-relevant rather than in-vitro. But the claims themselves stress these are raw report counts, not disproportionality statistics, subject to reporting bias and confounding, limiting rigor.', 'The reports describe nonspecific systemic adverse events (anxiety, depression, fatigue) and provide no information about ethinyl estradiol''s molecular target or specificity of action. The claims explicitly note no causation can be inferred.', 'Mood-related adverse events (anxiety, depression) plausibly relate to estrogen action on mood-regulating systems relevant to PMDD, as the claims suggest a ''mechanistic lead.'' However, this fit is weak and speculative given the data are uncontrolled report counts.', 'All three signals (anxiety, depression, fatigue) point in the same direction—mood/affective disturbance—consistent with a CNS-active mechanism. There is no contradictory signal among the claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, NULL, false, 'abstract', 'FDA AEMS spontaneous reports record thousands of anxiety, depression, and fatigue events for ethinyl estradiol in female patients, raw counts that flag mood-relevant adverse events but cannot establish causation.', 'Ethinyl estradiol acts on estrogen-sensitive CNS/mood-regulating pathways, which could relate to PMDD-relevant affective symptoms but here manifests as anxiety/depression adverse-event signals.', '{620021af-39f1-4224-9459-bbb9458b862d,508fd707-70ab-405f-a952-1954898a4c98,7e7d172f-1212-4533-b2e4-0170a4f6d444}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:13.117099+00:00', '2026-06-16T18:12:13.117109+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('595041f3-ed1f-49e0-a05f-65efdf2f5ccb', 'e5e1c9ed-6926-4b12-a042-0ad4890672b2', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'safety', 'pathway', 1, 1, 0, 1, 2, 'Three related signals (anxiety, depression, fatigue) all derive from the same single data source (FDA AEMS), so they are not truly independent mechanistic lines. They converge on a CNS/mood-relevant signal but represent one reporting database rather than multiple converging methodologies.', 'Data are from human spontaneous adverse-event reports (FDA AEMS), which is human-relevant and recent (retrieved 2026), but the claims explicitly state these are raw counts subject to reporting bias and confounding, not disproportionality statistics or causal evidence. This caps rigor below the level of controlled human data.', 'The claims report only adverse-event counts and offer no information about drospirenone''s molecular target or specificity of action; they merely note the drug ''acts on a system relevant to PMDD'' without target identification.', 'Mood-related events (anxiety, depression) plausibly relate to a progestin acting on systems relevant to PMDD, supporting a loose target-phenotype fit. However, the claims frame these as safety signals/leads rather than demonstrating a mechanistic pathway, so plausibility is only partial.', 'All three signals (anxiety, depression, fatigue) point in the same direction—toward CNS/mood-relevant adverse effects—with no contradictory data among the verified claims. The signals are internally consistent in implicating a mood/affect-related system.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, NULL, false, 'abstract', 'FDA adverse-event reports for drospirenone among female patients show thousands of mood-related events (7113 anxiety, 1957 depression, 1244 fatigue), which are raw uncontrolled counts suggesting the drug acts on a PMDD-relevant system rather than demonstrating benefit or causation.', 'Drospirenone may modulate CNS/affective systems relevant to PMDD, as suggested by the predominance of mood-related (anxiety, depression) adverse-event reports in female patients.', '{4645a279-6dd7-4053-b656-7b8b63115cd5,8db026a3-ef92-4e93-8a0e-b7a59f63473e,1932916a-b04f-435c-a9f7-e8234f29e5d0}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:13.155407+00:00', '2026-06-16T18:12:13.155416+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('42ab5e46-2db6-459b-ab39-e47d7a603044', '2e979d12-b11d-4e77-99d7-6171b6fda089', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'safety', 'pathway', 1, 1, 1, 2, 2, 'Two independent data sources converge — FDA AEMS spontaneous reports (claims 1-3) and SIDER label-derived frequencies (claims 4-6) — both flagging mood and fatigue signals. However, both are pharmacovigilance/label associations rather than distinct mechanistic lines, limiting true mechanistic convergence.', 'Evidence is from human-derived sources (FDA AEMS reports among female patients and SIDER label frequencies), which are human-relevant, but they are raw report counts and label associations with no disproportionality statistics, no controls, and explicit caveats about reporting bias and confounding (claims 1-6). This is hypothesis-generating rather than rigorous.', 'The claims clearly attribute the events to LEVONORGESTREL specifically (claims 1-6), but they describe broad neuropsychiatric/affective side effects (fatigue, anxiety, depression, mood swings, affect lability) without identifying a specific molecular target or progesterone-receptor mechanism. The action on the relevant system is asserted but not pinned to a target.', 'Mood swings, affect lability, anxiety, and depression are directly relevant to PMDD''s affective phenotype, and a progestin plausibly modulates the hormonal/neuroactive-steroid system implicated in PMDD (claims 2, 3, 5, 6). The target-phenotype fit is strong even though these are framed as adverse-event signals.', 'Both sources point in the same direction: AEMS shows fatigue, anxiety, and depression reports, while SIDER lists fatigue, mood swings, and affect lability (claims 1-6). The affective/fatigue signals are mutually reinforcing across sources with no contradictory data shown.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, NULL, false, 'abstract', 'Pharmacovigilance (FDA AEMS) and label (SIDER) data associate levonorgestrel with affective and fatigue-related adverse events in women, which are noted as safety considerations and as mechanistic leads relevant to PMDD''s symptom domains, not as evidence of benefit.', 'Levonorgestrel acts on the hormonal/neuroactive-steroid system governing mood, plausibly perturbing affective regulation (mood swings, affect lability, depression, anxiety) relevant to PMDD pathophysiology.', '{271c13dd-bc5d-4c09-91dc-a99ebd49e98d,9aed69d7-e216-4a87-bc38-7bce0b5b7297,db31f643-5940-44b7-b6a5-39becbeb9ca3,bd34205f-3b0d-42f6-83db-337fb37a62be,96d95e6b-fe3d-4770-b624-83f0aa9f592c,77910874-1757-4e46-b16a-7f50ef3fdd61}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:15.952476+00:00', '2026-06-16T18:12:15.952742+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('1f3d18f8-8d11-4751-9cda-6e31a0f0295c', 'db078ae7-eba6-47b4-bb00-3c5cfb87fab6', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'safety', 'pathway', 0, 0, 0, 0, 1, 'The two claims are both raw single-report counts from FDA AEMS (abdominal distension, abdominal pain), not independent mechanistic lines converging on a pathway. No mechanistic data on how curcumin acts on any endometriosis-relevant target is provided.', 'Evidence is a spontaneous adverse-event reporting database with explicit caveats about reporting bias, confounding, and that the counts are not disproportionality statistics or evidence of causation. This is the weakest tier of evidence and provides no mechanistic model.', 'The claims describe nonspecific gastrointestinal adverse events (abdominal pain, distension) with no identified molecular target or mechanism of action on endometriosis pathways. There is no demonstration of curcumin acting specifically on any named target.', 'The claims only assert that GI symptoms ''suggest curcumin acts on a system relevant to endometriosis,'' which is speculative and not a coherent target-phenotype fit. Abdominal symptoms as adverse events do not establish a plausible mechanistic link to endometriosis pathophysiology.', 'The two reports both concern abdominal/GI symptoms, so they are mutually consistent in pointing to a GI signal. However, this is a trivial consistency given they are essentially the same type of single-report event and provide no directional mechanistic signal.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, 'few events (≈2)', false, 'abstract', 'FDA adverse-event reporting shows isolated single reports of abdominal distension and abdominal pain in female curcumin users, but these are raw counts subject to reporting bias and do not establish causation or a mechanism.', NULL, '{6cc937f9-c4e4-4961-b4b2-f8ce95c4e8ba,3da6e9e2-8283-4300-b209-8f6e514a8d79}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:24.849897+00:00', '2026-06-16T18:12:24.849936+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('5b91e73b-a082-4d7d-ab53-42fa00bb8cf1', '6ac3c4b2-178a-4b38-9c40-6adef793e2b8', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'safety', 'pathway', 1, 1, 0, 1, 2, 'Two distinct sources converge—FDA AEMS report counts (claims 1, 2) and SIDER label-derived side effects (claims 3, 4)—both pointing to gynecologic/abdominal symptoms. However, these are pharmacovigilance and label associations, not independent mechanistic lines, so convergence is limited.', 'Sources are human-derived (FDA AEMS reports and SIDER drug labels) rather than in-vitro, which lends some relevance. But raw report counts and label percentages are low-rigor signals subject to reporting bias and provide no causal or controlled inference.', 'None of the claims describe cabergoline''s specific dopamine-agonist action on any endometriosis-relevant target; they only list nonspecific symptoms (abdominal pain, distension, dysmenorrhoea) that could arise via many mechanisms.', 'The labeled side effect dysmenorrhoea (claim 4) and abdominal pain/distension signals (claims 1-3) overlap symptomatically with endometriosis presentation, suggesting the drug touches a relevant system. But the claims explicitly note these are not evidence of benefit, and no target-phenotype mechanism is established.', 'All four claims point in the same direction—cabergoline is associated with abdominal/gynecologic symptoms across both AEMS and SIDER. There are no conflicting signals among the verified claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'few events (≈59)', false, 'abstract', 'Cabergoline is associated with abdominal pain, abdominal distension, and dysmenorrhoea in pharmacovigilance and drug-label data, which are safety considerations and weak mechanistic leads but not evidence of benefit in endometriosis.', 'Cabergoline''s reported gynecologic and abdominal adverse effects suggest it acts on a system relevant to reproductive/abdominal tissue, but no specific endometriosis-related mechanism is established by these claims.', '{3865f8f2-bcb9-47ff-b231-c6c74bb636a7,f73fbfbd-d31b-479b-9b6e-65127dc84401,576a1839-7f51-4cdb-a765-9e012d1f96eb,2cbbfe1c-5c4f-4495-8271-51387f6f89c8}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:25.109416+00:00', '2026-06-16T18:12:25.109442+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('c99cc50d-859f-4ebe-968a-c60b4220238b', '8db8c878-b6f6-4c3a-8916-67ca943ad4da', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'safety', 'pathway', 1, 1, 0, 1, 2, 'Two related signals (abdominal pain, abdominal distension) from the same FDA AEMS source point to gastrointestinal/abdominal effects, but these are not independent mechanistic lines—they derive from one reporting database and likely overlap. No distinct mechanistic pathways converge.', 'The data come from human adverse-event reports in the FDA AEMS system, which is human-relevant but acknowledged in the claims as raw counts subject to reporting bias and confounding, not disproportionality statistics or causal evidence. This places it above in-vitro but well below rigorous controlled data.', 'The claims describe nonspecific abdominal symptoms (pain, distension) and provide no information about danazol''s molecular target or mechanism of action. There is no evidence of specific action on any named target relevant to endometriosis.', 'Abdominal pain and distension are plausibly related to a drug used for endometriosis, since the condition itself involves pelvic/abdominal symptoms, making target-phenotype overlap reasonable. However, the claims explicitly note these are safety signals, not evidence of benefit, and causation is unestablished.', 'Both signals (abdominal pain and abdominal distension) point in the same direction toward abdominal/gastrointestinal involvement and are drawn from the same dataset with consistent framing. There is no conflicting signal among the claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'few events (≈55)', false, 'abstract', 'FDA adverse-event reports for danazol in female patients include 34 reports of abdominal pain and 21 of abdominal distension, representing raw safety signals without causal or disproportionality analysis.', 'Danazol may act on abdominal/pelvic systems relevant to endometriosis, with abdominal pain and distension as nonspecific manifestations, though no specific target mechanism is established by these claims.', '{d7437c50-2ed8-4d9e-a069-1df67b0516ba,33ed2256-36ae-4326-bfb4-c147b6a63b44}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:27.440520+00:00', '2026-06-16T18:12:27.440540+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('01e07ffe-c980-47ef-b0cc-f075896819d4', 'd0459f01-02b2-41b4-ac46-47d365868a7d', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'safety', 'pathway', 0, 1, 0, 1, 1, 'Only a single line of evidence is present: a raw count of 182 abdominal-pain reports in FDA AERS. No independent mechanistic lines converge; the claim itself notes this is not a disproportionality statistic or evidence of causation.', 'The data come from a human pharmacovigilance database (FDA AERS), which is human-relevant, but the claim explicitly states it is a raw report count subject to reporting bias and confounding, with no causal or disproportionality analysis. This limits the strength of the model considerably.', 'Abdominal pain is a nonspecific adverse-event signal and does not localize desogestrel''s action to any specific molecular target relevant to endometriosis. The claim only hints it ''acts on a system relevant to endometriosis'' without specifying a mechanism or target.', 'Abdominal pain is plausibly related to gynecologic/pelvic systems involved in endometriosis, providing weak target-phenotype fit. However, the signal is a generic symptom and could reflect many unrelated causes, so the fit is only modestly supported.', 'There is only one signal, so directional consistency cannot be meaningfully assessed across lines. The single report-count is internally coherent but ambiguously interpreted as both a safety consideration and a mechanistic lead.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, 'few events (≈182)', false, 'abstract', 'FDA AERS recorded 182 abdominal-pain reports for desogestrel among 3470 female reports, a raw count that is a safety consideration but not evidence of causation.', 'Abdominal pain reports suggest desogestrel acts on pelvic/gynecologic systems relevant to endometriosis, but the link is unspecified and only a hypothesis-generating lead.', '{396da33c-7182-4523-8977-c0a7427afef0}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:35.551106+00:00', '2026-06-16T18:12:35.551324+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('924c1f41-831f-44e8-8d71-d60494c88616', 'dcd5ca46-ee57-4d35-b7e1-07b887d30b22', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'safety', 'pathway', 1, 1, 1, 1, 2, 'Three independent adverse-event signals (menorrhagia, abdominal distension, menstrual disorder) from FAERS converge on dienogest''s action on the female reproductive/menstrual system. However, all derive from the same data source and are raw report counts, so they represent one reporting line rather than truly independent mechanistic evidence.', 'The data are from human spontaneous reports (FAERS), which is human-relevant, but the claims explicitly state these are raw counts without disproportionality statistics, subject to reporting bias and confounding, and not evidence of causation. This pharmacovigilance signal is weak in rigor.', 'The menstrual-related events (menorrhagia, menstrual disorder) align with dienogest''s progestin action on the endometrium, suggesting on-target effects. Abdominal distension is non-specific, and the counts do not establish target specificity.', 'Menstrual disturbances are biologically plausible for a progestin used in endometriosis, since the drug acts on endometrial tissue and bleeding patterns. The claims frame these as mechanistic leads relevant to endometriosis rather than confirmed target-phenotype effects.', 'All three signals point in the same direction—menstrual/abdominal effects consistent with dienogest''s action on the female reproductive system. There are no contradictory signals among the verified claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'few events (≈8)', false, 'abstract', 'FAERS spontaneous reports record a small number of menstrual-related adverse events (menorrhagia, menstrual disorder, abdominal distension) for dienogest in female patients, consistent with its action on the reproductive system but not establishing causation.', 'As a progestin, dienogest acts on endometrial tissue and the menstrual cycle, which can produce bleeding-pattern disturbances—the same target system relevant to its therapeutic effect in endometriosis.', '{9538072b-6aa3-4fbb-ba70-47e1cf8682a7,b62aa35c-9c90-4f50-a44c-63b920b3456f,89dac53f-ff34-49fd-ac9d-8f5dc9aac30a}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:35.718825+00:00', '2026-06-16T18:12:35.718855+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('6434ae41-b6c8-4580-957b-7dbc3c3ca17c', 'd7a2a7e6-ec6f-47b9-be6e-9e9497963a9d', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'safety', 'pathway', 1, 1, 0, 1, 1, 'Two distinct adverse-event signals (weight increased, alopecia) are reported among female patients, offering two loosely related observations. However, these are raw FAERS report counts, not independent mechanistic lines, and neither establishes a pathway to PCOS.', 'Data come from FDA AEMS/FAERS spontaneous reports in human female patients, which is human-relevant but among the weakest evidence forms — explicitly noted as raw counts subject to reporting bias and confounding, with no disproportionality analysis.', 'The claims provide raw symptom counts (weight increased, alopecia) with no mechanism linking acetylcysteine to any specific molecular target relevant to PCOS. The quotes themselves describe these as leads, not specific target actions.', 'Weight increase and alopecia overlap with PCOS-relevant phenotypes (metabolic, androgenic/hair), giving a weak phenotype fit. But the claims are adverse events and offer no demonstrated target-phenotype mechanism.', 'Both signals are adverse events recorded in the same FAERS dataset, so they do not contradict each other. Yet they point toward potential harm/phenotypic effects rather than coherently demonstrating a single mechanistic direction for PCOS.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'few events (≈146)', false, 'abstract', 'FAERS spontaneous reports for acetylcysteine in female patients include 96 weight-increased and 50 alopecia reports, raw counts that are flagged as safety considerations and mechanistic leads, not evidence of causation or benefit for PCOS.', 'Adverse-event signals of weight gain and alopecia hint that acetylcysteine may interact with metabolic and androgen/hair-related systems relevant to PCOS, but no concrete target pathway is established.', '{c82bb4f9-f7f0-4043-b166-1bffb50d83fe,ad9b8ebf-c699-4782-ac9f-d480de84f660}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:38.583316+00:00', '2026-06-16T18:12:38.583345+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('c1389c81-354f-4ff4-a095-f6d9ba96ff84', '3a35025d-5a80-4b01-aede-b7ffd317ed28', '3d08eafb-9ddd-4669-a3bc-f80164f7f1c5', 'safety', 'pathway', 1, 1, 1, 2, 2, 'Three independent adverse-event signals (ovarian cyst, weight increased, infertility) from the same FDA AEMS source converge on clomiphene acting on the reproductive/ovarian system relevant to PCOS. However, all derive from a single pharmacovigilance database, limiting true independence of lines.', 'Data come from human reports in FDA AEMS (human-relevant), which favors a higher score, but each claim explicitly states these are raw counts, not disproportionality statistics, and are subject to reporting bias and confounding. This limits the strength of the model.', 'Ovarian cyst and infertility signals plausibly reflect clomiphene''s known action on the hypothalamic-pituitary-ovarian axis, supporting target relevance. But the counts are raw and unadjusted, so they do not specifically demonstrate the drug''s targeted action versus background reporting.', 'Ovarian cyst and weight changes fit well with clomiphene''s mechanism as an ovulation inducer acting on estrogen receptors and the ovarian axis, directly relevant to PCOS phenotype. The target-phenotype fit is strong even though causation is not established.', 'All three signals (ovarian cyst, weight increased, infertility) point in the same direction — clomiphene engaging the reproductive/metabolic system relevant to PCOS. No contradictory signals are present among the verified claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'few events (≈23)', false, 'abstract', 'Raw FDA AEMS counts among female patients on clomiphene citrate show ovarian cyst (23), weight increased (20), and infertility (16) reports, which serve as mechanistic leads relevant to PCOS but are not evidence of causation.', 'Clomiphene''s action on the estrogen-receptor/hypothalamic-pituitary-ovarian axis could produce ovarian cysts and metabolic/reproductive effects relevant to PCOS pathophysiology.', '{1096b47e-b3f8-4e85-a167-e6fd347eeb8d,00202c66-e8e0-487d-a00f-095c86ae3e20,fce883b5-5de2-4ae8-967d-9618b2406306}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:46.405749+00:00', '2026-06-16T18:12:46.405792+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('49a80cea-d2e0-47bb-b593-e009a00eb74f', 'df468fdc-297f-4a39-913c-8f0cf50ee3e5', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'pathway', 1, 1, 1, 1, 2, 'Two independent sources (FDA AEMS reporting counts and SIDER label data) both flag hot flush, providing some convergence. However, these are pharmacovigilance/label associations rather than distinct mechanistic lines, and all point to symptom-level signals (hot flush, insomnia, hyperhidrosis) rather than mechanistically independent pathways.', 'Evidence derives from human-relevant data sources (FDA AEMS reports among female patients and SIDER label-derived side effects), which is better than in-vitro. But these are raw report counts and label snapshots subject to reporting bias and confounding, explicitly noted as not causation, limiting rigor.', 'The claims concern bazedoxifene specifically, a SERM, and the vasomotor adverse events (hot flush, hyperhidrosis) are consistent with anti-estrogenic action on a menopause-relevant system. However, no molecular target (e.g., estrogen receptor) is named or characterized in the claims, so target specificity is only inferred.', 'Hot flush, insomnia, and hyperhidrosis are all phenotypically tied to estrogen-modulating effects, fitting the menopause context as the claims note. The fit is plausible but indirect, since these are adverse-event signals reframed as mechanistic leads, not direct evidence of a therapeutic mechanism.', 'All four claims point in the same direction: bazedoxifene is associated with vasomotor/menopausal-type symptoms (hot flush in two sources, plus insomnia and hyperhidrosis). There is no contradictory signal among the claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'few events (≈61)', false, 'abstract', 'Pharmacovigilance and label-derived sources associate bazedoxifene with hot flush, insomnia, and hyperhidrosis in female patients, signals relevant to menopause but reflecting adverse-event reporting rather than proven causation or benefit.', 'As a selective estrogen receptor modulator, bazedoxifene''s anti-estrogenic activity in certain tissues may provoke vasomotor symptoms (hot flush, hyperhidrosis) and sleep disturbance, indicating action on estrogen-regulated systems relevant to menopause.', '{a891f000-7bee-4287-9c09-c1a3ed19120e,a1126c4f-1502-4f66-9748-591a8fd4ce59,701f688f-c2d7-41be-8216-19d32047f153,204c7fc8-1c76-44bf-9ad5-874bc919fa81}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:49.597046+00:00', '2026-06-16T18:12:49.597069+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('afbfbc98-1038-402f-b409-58c155214864', '3956d951-aa1c-47d6-8dfd-024f5d6c617d', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'pathway', 1, 1, 0, 1, 1, 'Two independent data sources (FDA AEMS report counts and SIDER label-derived associations) converge on citalopram affecting vasomotor and thermoregulatory systems (hyperhidrosis, flushing, hot flush) plus sleep and mood. However, these are pharmacovigilance/label associations, not mechanistic pathway data, so convergence is observational rather than mechanistic.', 'Sources are human-derived (FDA AEMS female reports and pre-2015 drug labels via SIDER), which is more relevant than in-vitro work. But both are explicitly noted as raw report counts and label associations subject to reporting bias and not causation, and SIDER is a 2015 snapshot, limiting rigor.', 'None of the claims describe citalopram''s specific molecular target (SERT/serotonin transporter); they only list adverse-event categories. There is no characterization of target engagement or selectivity, so specificity cannot be supported.', 'The reported events—hot flush, flushing, hyperhidrosis, mood swings, insomnia—overlap with menopausal vasomotor and mood symptoms, suggesting citalopram acts on serotonergic systems involved in thermoregulation. The fit is suggestive but the claims frame this as a hypothesis-generating lead, not established target-phenotype mechanism.', 'Signals across both sources point toward thermoregulatory/vasomotor and mood/sleep effects, which is internally consistent. However, the direction is ambiguous as a safety reading (citalopram may cause these symptoms) versus a mechanistic lead, and low SIDER frequencies (0–1%) temper the strength.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, NULL, false, 'abstract', 'Pharmacovigilance and drug-label data show citalopram is associated with vasomotor and thermoregulatory adverse events (hot flush, flushing, hyperhidrosis) plus insomnia and mood swings in women, but these are uncontrolled report/label associations, not causal or mechanistic evidence.', 'Citalopram''s serotonergic action may influence central thermoregulatory pathways relevant to menopausal vasomotor symptoms, as suggested by adverse-event signals for hot flush, flushing, and hyperhidrosis.', '{b18b0b8c-52b1-46b8-a2b7-d51eeb340995,c9a2a2d5-99eb-4085-a919-63c25c168e5d,83b4d952-2813-4bef-b850-cc754610b99b,b45e3957-6a3c-4da7-ac7d-a6f129f9ad06,fd1473cb-6ac8-4545-b19b-c6cc4deb60a3}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:53.087664+00:00', '2026-06-16T18:12:53.087696+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('edca0b8b-a7d1-4fa4-beab-38d4fef4d155', 'bc13ec6f-16f8-4001-b8b1-a7b165519dc1', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'pathway', 1, 1, 1, 1, 2, 'Three distinct adverse-event signals (insomnia, hyperhidrosis, hot flush) among female reports converge on a vasomotor/thermoregulatory and sleep-relevant system, providing modest mechanistic convergence. However, all three derive from the same FAERS pharmacovigilance source and represent raw counts, so they are not truly independent lines of evidence.', 'The data come from FDA AEMS/FAERS, a human-derived spontaneous reporting system, which is human-relevant but among the weakest designs. The claims themselves note these are raw counts subject to reporting bias and confounding, with no disproportionality statistic or causal inference.', 'Desvenlafaxine is an SNRI with a known mechanism relevant to thermoregulation, but the FAERS counts only catalog adverse events and do not demonstrate specificity of action on a named menopause-relevant target. The link to the relevant system is inferential rather than directly established.', 'Hot flush and hyperhidrosis are core vasomotor menopausal symptoms, and the appearance of these as adverse events plausibly indicates the drug acts on thermoregulatory pathways relevant to menopause. The fit is suggestive but the claims explicitly frame this as a mechanistic lead, not evidence of benefit or causation.', 'All three signals (insomnia, hyperhidrosis, hot flush) point coherently toward involvement in thermoregulatory and sleep systems relevant to menopause. There is no contradictory direction among the verified claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, NULL, false, 'abstract', 'FAERS spontaneous reports for desvenlafaxine succinate in female patients include insomnia, hyperhidrosis, and hot flush events, which are raw counts suggesting action on thermoregulatory/sleep systems relevant to menopause but not evidence of causation or benefit.', 'As an SNRI, desvenlafaxine modulates noradrenergic/serotonergic signaling involved in central thermoregulation, plausibly explaining both vasomotor (hot flush, hyperhidrosis) and sleep-related (insomnia) adverse-event signals.', '{c25f3cbb-7a77-4064-98bd-5c34afd025c3,441e441c-d5c9-4d8f-b1d3-bd2656f8fdc6,cc9d92cf-9e38-453f-a655-64e4633634bf}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:12:59.581501+00:00', '2026-06-16T18:12:59.581531+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('39dbfc2c-e039-4382-a25b-135c57a96398', 'f02367ca-3bca-43af-80db-0a713a8ba6d7', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'pathway', 1, 1, 1, 1, 1, 'Three independent adverse-event signals (insomnia, hyperhidrosis, flushing) are reported among female escitalopram users, and these vasomotor/sleep symptoms are mechanistically relevant to menopause. However, all derive from the same FAERS data source and are raw counts without disproportionality analysis, limiting true independence.', 'The data are human-derived (FDA FAERS reports in female patients), which is more relevant than in-vitro work, but they are uncontrolled spontaneous reports explicitly flagged as subject to reporting bias and confounding with no causal inference. This is weak observational pharmacovigilance signal, not a rigorous model.', 'The reports name escitalopram specifically and the symptom types (hyperhidrosis, flushing) are plausibly tied to serotonergic action on thermoregulation, but raw counts cannot localize the drug''s action to a specific target. No mechanistic specificity is demonstrated.', 'Hyperhidrosis and flushing overlap with menopausal vasomotor symptoms, supporting a thermoregulatory-pathway link consistent with SSRI use in menopause. The fit is suggestive but the claims explicitly note these are adverse-event signals, not evidence of benefit, so the target-phenotype direction is ambiguous.', 'All three signals come from the same dataset and are flagged negative (safety) yet framed as mechanistic leads, creating directional ambiguity—the same vasomotor symptoms are both an indication target and a reported adverse event. The signals are internally consistent in pointing to a thermoregulatory/serotonergic system, but their interpretation is not uniform.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, NULL, false, 'abstract', 'FAERS spontaneous reports show insomnia, hyperhidrosis, and flushing among female escitalopram users, which are vasomotor/sleep symptoms relevant to menopause but represent uncontrolled adverse-event counts, not causal or benefit evidence.', 'Escitalopram''s serotonergic modulation affects thermoregulatory and sleep pathways, producing flushing, sweating, and insomnia signals that overlap with menopausal vasomotor symptomatology.', '{5a91cbea-7ac1-4dca-9bc9-4236fcfff617,caa1fc76-2182-4df9-909a-724e8ff0c068,a29e2859-4fc1-40d3-bf97-368e68c243b3}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:13:04.248798+00:00', '2026-06-16T18:13:04.248835+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('7de224ea-d00e-4ed9-b4f1-45c38921347b', '041510d6-ac3c-4f73-8511-df8e44d5eb60', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'pathway', 1, 1, 1, 1, 2, 'Two independent data sources converge (FDA AEMS spontaneous reports and SIDER label-derived associations), and both flag overlapping signals such as hot flush/flushing and hyperhidrosis (claims 2-5). However, these are pharmacovigilance and label associations rather than distinct mechanistic lines, limiting the depth of convergence.', 'Evidence derives from human-relevant real-world sources (FAERS reports among female patients and human drug labels), which is better than in-vitro data, but both are explicitly described as raw counts/label associations subject to reporting bias and confounding, with no disproportionality statistics (claims 1-6).', 'The signals are attributed specifically to ESTRADIOL in each source, but the listed events (insomnia, hot flush, hyperhidrosis, vaginal discharge) overlap with menopausal symptoms themselves and are not tied to a specific molecular target/action, leaving causation and target-specificity unestablished (claims 1-6).', 'The events cited (hot flush, hyperhidrosis, insomnia) are thermoregulatory/sleep phenomena consistent with estradiol acting on systems relevant to menopause, as each claim notes (claims 1-3). But these may reflect underlying disease or confounding rather than a coherent drug-induced phenotype, so the target-phenotype fit is only moderate.', 'The signals point in the same direction across sources: vasomotor/sudomotor events (hot flush/flushing, hyperhidrosis) appear in both FDA AEMS and SIDER (claims 2-5), with no contradictory signals presented. The two datasets corroborate one another qualitatively.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, NULL, false, 'abstract', 'Pharmacovigilance (FDA AEMS) and label-derived (SIDER) data record estradiol-associated reports of vasomotor and related symptoms (hot flush, hyperhidrosis, insomnia, vaginal discharge) in female patients, but these are uncontrolled association counts, not evidence of causation.', 'Estradiol acts on thermoregulatory and reproductive-tract systems, plausibly explaining reported vasomotor (hot flush/flushing), sudomotor (hyperhidrosis), sleep (insomnia), and vaginal discharge signals.', '{9b0cd174-a38e-40d2-9543-f008f63e89ab,2ee108f6-12cb-4764-81e0-e96580f66bd4,6e4250da-107e-4a26-9ea9-770a13c19e96,d136710c-cb74-438e-be6e-63269930eff4,b838043c-66df-475f-b71c-b3b994c8a913,c95209de-23e9-4f95-b24e-15919b3f2695}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:13:07.618682+00:00', '2026-06-16T18:13:07.618701+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('3e9b8da4-4446-473f-bbfd-9aca935e37d4', 'df5d26db-e34e-4e16-bb63-7539985cc236', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'efficacy', 'community', 0, 0, 1, 0, 1, 'Independence (patient accounts): 0 distinct account(s) across 1 thread(s) (author handles unavailable — counting distinct posts).', 'The single claim is vague: it states ''barely felt any PMDD symptoms this month'' but gives no lysine dose, timing relative to cycle, duration, or which specific symptoms improved. There is no specificity beyond a general impression.', 'The drug (lysine) and the outcome (reduced PMDD symptoms) are both named and linked. However, the link is loose and incidental—lysine was taken for a cold sore, not PMDD—so the connection is suggestive rather than clearly intentional.', 'Lysine is an amino acid used for herpes/cold sores; there is no established pharmacological mechanism by which it would modulate the cyclical mood/somatic symptoms of PMDD. The reported effect could easily be coincidental or placebo, and no plausible mechanism is supported by the claim.', 'With only one report there is nothing to contradict, and the single account is internally coherent. However, no dose/timing detail is provided and there are no corroborating reports to assess agreement, so coherence cannot be strongly established.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, NULL, false, 'abstract', 'A single self-reported anecdote noted markedly reduced PMDD symptoms during a month when lysine was taken for a cold sore.', NULL, '{ebd869df-fa85-48c1-8ae5-9b2a597382e8}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:21:37.759805+00:00', '2026-06-16T18:21:37.760221+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('9b150c77-bd52-48e4-8101-632473b439f2', 'b73efe40-fe57-43fd-b7fb-a0087b37a3a4', '13c33c1b-98d6-4ef0-bb1a-add1344261a5', 'efficacy', 'community', 0, 0, 1, 1, 1, 'Independence (patient accounts): 0 distinct account(s) across 1 thread(s) (author handles unavailable — counting distinct posts).', 'The report is vague: it offers an enthusiastic label (''miracle drug'') with no symptom detail, dose, timing, or duration of use. Nothing specific is provided to anchor the claim.', 'The drug (Meloxicam) is clearly named and an effect is asserted, but the outcome is only loosely described as helping ''their condition'' without naming endometriosis-specific symptoms. The drug-outcome link is implied rather than explicitly detailed.', 'Meloxicam is an NSAID, and NSAIDs are commonly used to reduce prostaglandin-mediated dysmenorrhea/pelvic pain in endometriosis, so a pain benefit is pharmacologically plausible. However, the claim lacks detail to assess whether the reported effect aligns with NSAID action.', 'There is only one report, so there is no disagreement, but also no confirming independent reports. Dose/timing coherence cannot be assessed because none is provided.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, NULL, false, 'abstract', 'A single patient reported that meloxicam was highly effective for their endometriosis-related symptoms, describing it as a ''miracle drug.''', 'As an NSAID, meloxicam may reduce prostaglandin-mediated inflammation and pelvic pain associated with endometriosis.', '{e278af9a-3868-428f-977f-80b266acaf5e}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:21:40.361108+00:00', '2026-06-16T18:21:40.361130+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('d84738a3-daae-466d-b452-c4e0772c974d', '92bac47c-bc1f-4b7f-b0e9-d5459c82989d', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'community', 0, 0, 0, 1, 1, 'Independence (patient accounts): 0 distinct account(s) across 1 thread(s) (author handles unavailable — counting distinct posts).', 'The report is entirely vague: it states only that ''this helped my menopause symptoms'' with no specific symptom, dose, timing, or duration. There is no detail to assess the report''s quality.', 'The intervention is unspecified and the outcome (''menopause symptoms'') is generic. Drug and outcome cannot be clearly linked because the drug is not identified.', 'Without an identified intervention, pharmacological plausibility cannot be properly assessed. The claim that something helped menopause symptoms is generically plausible but unsupported by any mechanistic detail.', 'There is only one report, so there is no disagreement, but also nothing to confirm internal coherence of dose/timing. A single positive statement is trivially self-consistent but uninformative.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Exploratory', false, 0, NULL, false, 'abstract', 'A single community member reported that an unspecified treatment helped their menopause symptoms.', NULL, '{0910067d-6979-4856-a159-40f0b379ad27}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:21:45.680036+00:00', '2026-06-16T18:21:45.680079+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('de442072-fdce-46a3-9b05-abe087404260', '1ee8c502-ea12-4812-8209-790c92b5f0a2', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'efficacy', 'community', 0, 1, 1, 1, 1, 'Independence (patient accounts): 0 distinct account(s) across 1 thread(s) (author handles unavailable — counting distinct posts).', 'The report links creatine to brain fog and mentions a dose-response (''until I drastically increased the dosage''), but provides no specific dose amount, timing, or duration. This is partial specificity at best.', 'The drug (creatine) and outcome (menopause-associated brain fog) are both named and linked. However, the dose is vague (''drastically increased'') and the effect at the higher dose is implied rather than clearly stated.', 'Creatine has plausible CNS bioenergetic effects that could affect cognitive symptoms like brain fog, and a dose-dependent response is biologically conceivable. The single anecdote provides only weak support for this pharmacological rationale.', 'The single report is internally coherent: no benefit at low dose, implied benefit after dose increase. There are no other accounts to confirm or contradict, so consistency cannot be fully assessed.', 'F1', 1.0, 'Evidence generated in women (female population).', 'Emerging', false, 0, NULL, false, 'abstract', 'A single user reported that creatine had no effect on menopause-associated brain fog at the initial dose but implied improvement after substantially increasing the dosage.', 'Higher-dose creatine may enhance brain bioenergetic capacity, potentially improving cognitive symptoms like brain fog only above a threshold dose.', '{5505c389-0c2a-434e-862a-82e3c8807bc3}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:21:48.136233+00:00', '2026-06-16T18:21:48.136273+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('0723fdf9-f535-4ec8-85ba-84d550f3fd2a', '7330eec6-af95-4731-a824-f9eca7fc8ae6', '61143789-de48-488b-968b-f3f71189f1bc', 'safety', 'pathway', 0, 0, 0, 0, 1, 'Only a single line of evidence is presented: a raw adverse-event report count of abdominal pain for aspirin in female patients from FDA AEMS. There are no independent mechanistic lines converging, and the claim itself acknowledges it is not a disproportionality statistic or causal evidence.', 'The data is a raw pharmacovigilance report count subject to reporting bias and confounding, with no analytic model applied. The single claim explicitly states it is ''not a disproportionality statistic or evidence of causation.''', 'Abdominal pain is a nonspecific symptom and the claim does not link aspirin''s action to a specific molecular target relevant to adenomyosis. No specific mechanism on a named target is described.', 'The claim provides only an indirect, speculative ''mechanistic lead'' inference from an adverse-event count, not a demonstrated target-phenotype fit for adenomyosis. Abdominal pain reports do not establish a plausible mechanism specific to adenomyosis.', 'There is only one signal (abdominal pain reports), so there are no conflicting signals, but a single non-causal count cannot demonstrate that multiple signals point the same way. Consistency is essentially indeterminate from one data point.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, NULL, false, 'abstract', 'FDA AEMS recorded 4647 raw abdominal pain reports for aspirin among female patients, a non-causal safety/mechanistic signal that does not establish any relationship to adenomyosis.', NULL, '{a529a875-bcb6-4c4f-a2e5-166191ebced9}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:29:21.990833+00:00', '2026-06-16T18:29:21.990862+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('91debb5b-1b6c-492d-87e8-9de9c67e757f', '4f298539-db26-48e8-b86e-bbc7c69884a9', 'e3758034-fa92-40a3-af17-80fbbdecb0d6', 'safety', 'pathway', 0, 1, 0, 1, 1, 'Only a single line of evidence is present: a raw FAERS adverse-event count of 13 insomnia reports. No independent mechanistic lines converge; the claim itself states this is not causation or disproportionality.', 'The data come from a human pharmacovigilance database (FDA AEMS/FAERS), which is human-relevant, but it is uncontrolled spontaneous reporting subject to reporting bias and confounding, as the claim explicitly notes. This is weak observational evidence, not a rigorous model.', 'The claim provides only a raw event count for insomnia and offers no mechanistic detail about estradiol valerate acting on any specific target. No specificity of drug-target action is demonstrated.', 'Insomnia is plausibly linked to estrogen action on systems relevant to menopause, and the claim suggests this as a mechanistic lead. However, the connection is speculative and not substantiated by mechanistic data.', 'There is only one signal (insomnia reports), so there are no conflicting signals, but neither is there convergence of multiple signals. A single uncorroborated count cannot establish directional consistency.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Exploratory', false, 0, 'few events (≈13)', false, 'abstract', 'FDA adverse-event reporting recorded 13 insomnia reports among 863 female estradiol valerate reports, a raw count that is not evidence of causation.', 'Estradiol valerate may act on estrogen-sensitive systems involved in sleep regulation relevant to menopause, but this is only a speculative lead from raw adverse-event signals.', '{73eb2d66-afb7-4eeb-8561-75c5ca918d99}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:29:23.121145+00:00', '2026-06-16T18:29:23.121174+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('a6776e2f-819a-4841-af56-6a66496a33a1', '7f6ed8f9-842a-42ca-b224-7ca9e3fcf95a', 'fc6df098-33bb-45d7-a203-fdb0dc5095b1', 'safety', 'pathway', 1, 1, 1, 1, 2, 'Two independent data sources converge (FDA AEMS spontaneous reports and SIDER label-derived side effects), each listing overlapping neuropsychiatric/constitutional events like fatigue and anxiety. However, these are pharmacovigilance and label associations rather than independent mechanistic lines, so convergence is modest.', 'Sources are human-derived (FDA AEMS reports among female patients; SIDER from drug labels), which is human-relevant. But both are explicitly disproportionality-free raw counts/label associations subject to reporting bias and confounding, and SIDER is a pre-2015 snapshot, limiting rigor.', 'Claims state these events suggest sertraline ''acts on a system relevant to PMDD'' but provide no molecular target detail; the adverse events (fatigue, anxiety, depression, mood swings) are generic neuropsychiatric effects consistent with serotonergic action without pinning specificity to the named target.', 'The reported events—anxiety, depression, mood swings—overlap with the affective symptom domain of PMDD, giving a plausible target-phenotype fit. Yet these are listed as adverse effects, so they cut both ways and the fit to PMDD benefit is only suggestive.', 'Both FDA AEMS and SIDER point in the same direction: fatigue and anxiety appear in both sources, and the affective side effects (depression, mood swings) are consistent with a neuropsychiatric mechanistic signal. No contradictory signals are present.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, NULL, false, 'abstract', 'Pharmacovigilance (FDA AEMS, female reports) and label data (SIDER) record fatigue, anxiety, depression, and mood swings as sertraline-associated adverse events, indicating sertraline acts on neuropsychiatric systems relevant to PMDD but with no causal or benefit inference.', 'Sertraline''s serotonergic action affects mood/affective regulatory systems, producing neuropsychiatric effects that overlap with the symptom domain targeted in PMDD.', '{5088e22f-2fa4-4829-be5f-0175d6bcfa8c,f3b785a6-d16e-4349-b8fc-98b0c50a8104,355a72e6-94ef-4c36-adbc-ba2a95b347bd,9da650c7-1ef2-4a38-9ddf-a29669cabd45,46c11143-4dd1-42aa-bbca-1f4127cafbb3,1ed06829-cfc1-4aec-8d38-8c788ddb15a9}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:29:27.053416+00:00', '2026-06-16T18:29:27.053447+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('707a2266-6166-49f7-9ac0-4c4e774006e2', 'e5e1c9ed-6926-4b12-a042-0ad4890672b2', '61143789-de48-488b-968b-f3f71189f1bc', 'safety', 'pathway', 1, 1, 0, 1, 2, 'Two distinct adverse-event signals (abdominal pain, menorrhagia) from the same FAERS source converge on the pelvic/uterine system relevant to adenomyosis, providing weak corroboration. However, both derive from a single data source and are raw report counts, not independent mechanistic lines.', 'The data are human-derived (FDA AEMS female reports), which is more relevant than in-vitro work, but the claims explicitly state these are raw counts without disproportionality statistics, subject to reporting bias and confounding. This limits rigor substantially.', 'The claims report associations only and explicitly state they are not evidence of causation. No specific molecular target or mechanism of drospirenone''s action on the uterus is identified, so specificity of drug action cannot be supported.', 'Menorrhagia and abdominal pain are phenotypically aligned with adenomyosis symptomatology, suggesting drospirenone acts on a relevant system. But the claims frame this only as a mechanistic lead, not established target-phenotype fit.', 'Both reported signals (abdominal pain and menorrhagia) point in the same direction — toward effects on the uterine/pelvic system relevant to adenomyosis. There is no contradictory signal among the verified claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, NULL, false, 'abstract', 'Drospirenone has raw FAERS reports of abdominal pain (2884) and menorrhagia (542) among female patients, which are uncausal safety signals on a uterine system relevant to adenomyosis but not evidence of benefit.', 'Adverse-event reports of menorrhagia and abdominal pain suggest drospirenone acts on the uterine/endometrial system, a system implicated in adenomyosis, though no specific target is established.', '{6740ca3e-819c-4c47-b99a-4500ebc7d808,0c03ff28-65fb-44ec-a92c-756912921ee5}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:29:35.520863+00:00', '2026-06-16T18:29:35.520947+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('cb20b449-18a9-4090-ab3d-6b4bdf468da4', 'dcd5ca46-ee57-4d35-b7e1-07b887d30b22', '61143789-de48-488b-968b-f3f71189f1bc', 'safety', 'pathway', 1, 1, 1, 1, 2, 'Three separate adverse-event signals (menorrhagia, menstrual disorder, abdominal pain) from a single source (FDA FAERS) all relate to the gynecologic/menstrual system, providing weak convergent signals that dienogest acts on a system relevant to adenomyosis. However, these are all from one database and represent raw report counts, not independent mechanistic lines.', 'The data come from human adverse-event reports (FAERS) in female patients, which is human-relevant, but the claims themselves explicitly state these are raw counts subject to reporting bias and confounding, with no disproportionality statistics or causal analysis.', 'The reported events (menorrhagia, menstrual disorder) are plausibly tied to dienogest''s progestin action on the endometrium, but the source provides no mechanistic detail on target action; the link to a specific molecular target is only inferred from the symptom class.', 'Menstrual/uterine bleeding symptoms and abdominal pain are phenotypically relevant to adenomyosis, supporting a target-phenotype fit at the organ-system level. However, the claims describe these as adverse events, not therapeutic effects, so the fit toward benefit is weak and indirect.', 'All three signals (menorrhagia, menstrual disorder, abdominal pain) point consistently toward involvement of the menstrual/uterine system, with no contradictory signals among the verified claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, 'few events (≈13)', false, 'abstract', 'FDA FAERS contains a small number of raw adverse-event reports (menorrhagia, menstrual disorder, abdominal pain) for dienogest in female patients, suggesting action on a menstrual/uterine system relevant to adenomyosis but providing no causal or disproportionality evidence.', 'Dienogest, a progestin, acts on the endometrium/uterine system, which is reflected in menstrual and abdominal adverse-event reports and is the same system implicated in adenomyosis.', '{48059f9a-a19b-4f34-bf96-992ecebfb94e,d0a7a145-0042-4bc1-99b3-b8e01c7d92e8,dcd65927-36d7-458f-87e8-dc0544747922}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:29:35.906764+00:00', '2026-06-16T18:29:35.906793+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('0b0e4ed9-dd89-46a4-aec1-d66b8ee72cfe', '54c47e3b-d531-48be-963f-26682921e21d', '61143789-de48-488b-968b-f3f71189f1bc', 'safety', 'pathway', 1, 1, 1, 1, 1, 'Two independent data sources converge — FDA AEMS spontaneous reports and SIDER label-derived side effects — both pointing to gynecologic/abdominal symptoms (claims 1-4). However, these are pharmacovigilance/label associations rather than mechanistic lines, and they describe overlapping symptom classes rather than distinct mechanisms.', 'Data are human-relevant (FDA adverse-event reports among female patients and human drug labels per claims 1-4), which supports a moderate score. But they are raw report counts and pre-2015 label snapshots with explicit caveats about reporting bias, confounding, and no disproportionality statistic, limiting rigor.', 'Goserelin is a specific GnRH agonist, and the reported effects (dysmenorrhoea, menorrhagia, abdominal pain in claims 1,3,4) plausibly relate to its hormonal action on the reproductive system. The claims themselves only assert the drug ''acts on a system relevant to adenomyosis'' without characterizing target binding specificity.', 'The gynecologic symptoms (dysmenorrhoea, menorrhagia, abdominal pain — claims 1,3,4) overlap with adenomyosis symptomatology, indicating the drug engages a relevant reproductive system. The signals are presented as adverse events rather than as a clear beneficial mechanistic fit, so the phenotype link is suggestive but ambiguous in direction.', 'All four claims point to uterine/abdominal symptom domains, showing directional alignment in the affected system (claims 1-4). However, claim 2 reports abdominal pain at 0% while claim 1 reports 110 AEMS abdominal pain reports, an apparent tension in magnitude across sources.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Emerging', false, 0, 'few events (≈110)', false, 'abstract', 'Pharmacovigilance and label data for goserelin in female patients report gynecologic and abdominal adverse events (abdominal pain, dysmenorrhoea, menorrhagia), which are raw associations and not evidence of causation or benefit in adenomyosis.', 'As a GnRH agonist, goserelin suppresses the hypothalamic-pituitary-gonadal axis affecting the uterine/reproductive system, consistent with the gynecologic adverse-event signals and relevant to adenomyosis pathophysiology.', '{c15fbfff-5d57-4c78-91cd-70bf7f16ad44,08710400-e509-4263-a2aa-6af8d7c2016d,1bff80be-4be4-4b72-9693-843f8b5c306a,5d0f89f1-ba1f-4b6e-94ec-54048f4b8a94}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:29:39.896174+00:00', '2026-06-16T18:29:39.896215+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
INSERT INTO substrate_signals (id, intervention_id, condition_id, aspect, arm, corroboration_score, rigor_score, specificity_score, plausibility_score, consistency_score, corroboration_rationale, rigor_rationale, specificity_rationale, plausibility_rationale, consistency_rationale, female_applicability_band, female_applicability_multiplier, female_applicability_rationale, confidence_tier, contradiction_flag, num_contradictions, precision_note, needs_fulltext, source_tier, synthesis_summary, mechanism_hypothesis, claim_ids, model_name, prompt_hash, status, off_topic_reason, created_at, updated_at) VALUES ('0d2d7fa7-0f20-4455-adbe-66890b6db186', '97cc587b-f617-4589-b1df-9139f8a7ca7d', '61143789-de48-488b-968b-f3f71189f1bc', 'safety', 'pathway', 1, 1, 1, 1, 2, 'Two independent pharmacovigilance/label sources (FDA AERS and SIDER) both report abdominal pain associated with letrozole, providing converging but homogeneous signals. Both are surveillance/label associations rather than distinct mechanistic lines, so corroboration is modest.', 'The data are human-derived (FDA AEMS report counts among 43325 female reports, and SIDER label data showing 5.0% incidence), which is more relevant than in-vitro work. However, both are uncontrolled association/reporting sources explicitly described as not evidence of causation, limiting rigor.', 'Letrozole is a specific aromatase inhibitor, but the cited claims describe only abdominal pain as an adverse event without linking to a specific molecular target action on adenomyosis tissue. The signal is a nonspecific symptom rather than a targeted mechanistic readout.', 'Abdominal pain reports plausibly indicate letrozole acts on systems relevant to a pelvic/uterine condition like adenomyosis, as the claims note. But abdominal pain is a generic symptom and does not clearly map onto an adenomyosis-specific phenotype, so the target-phenotype fit is only partial.', 'Both sources point in the same direction, identifying abdominal pain as an associated adverse event for letrozole in female patients. There is no conflicting signal across the two claims.', 'F1', 1.0, 'Evidence generated in women (female population, ~100% female).', 'Moderate', false, 0, NULL, false, 'abstract', 'Pharmacovigilance and drug-label sources show abdominal pain as an adverse event associated with letrozole in female patients (755 FDA reports; 5.0% on label), framed as a safety consideration and a mechanistic lead rather than proof of effect on adenomyosis.', 'Letrozole-associated abdominal pain may reflect aromatase inhibition reducing estrogen activity in pelvic/uterine tissue, a system relevant to adenomyosis.', '{fe2222e4-492c-476a-9810-4843432983ae,aeadd75e-7484-49ed-97b4-82234b057b7b}', 'claude-opus-4-8', 'b2637a5f35001f42', 'active', NULL, '2026-06-16T18:29:42.737053+00:00', '2026-06-16T18:29:42.737086+00:00') ON CONFLICT (intervention_id, condition_id, aspect, arm) DO NOTHING;
